Definition 1: For any $p,x>0$ and $i\in [k]$, we say that $(t_1,t_2)$ is a $(p,q,x)$-\emph{segment}  if there exists a subset $\mathcal{I}\subseteq [k]$  such that 
%
\begin{itemize}
	\item[$\mathrm{(i)}$] $\sum_{ i\in \mathcal{I}}w^{t_1}_{i}\in \left[p/2 ,p\right]$, 
	\item[$\mathrm{(ii)}$] $\sum_{i\in \mathcal{I}}w^{t_2}_i \geq p \exp(x)$,  
	\item[$\mathrm{(iii)}$] $\sum_{i\in \mathcal{I}}w_i^{t}\geq  q$ for any $t_1\leq t\leq t_2$. 
\end{itemize}
%
We shall refer to $t_1$ as the starting point and $t_2$ as the end point, and call $\mathcal{I}$ the associated index set. Moreover,  two segments $(s_1,e_1)$ and $(s_2,e_2)$ are said to be disjoint if $s_1<e_1 \leq s_2<e_2$ or $s_2<e_2\leq s_1<e_1$. 
Lemma 13 (Fact): Let $X_1,X_2,\ldots$ be a sequence of random variables taking value in the interval $[0,l]$. 
For any $k\geq 1$, let $\mathcal{F}_k$ be the $\sigma$-algebra generated by $(X_1,X_2,\ldots,X_k)$, and define 
	$Y_k := \mathbb{E}[X_k \mid \mathcal{F}_{k-1}]$. Then for any $\delta>0$, we have 
%
\begin{align}
	& \mathbb{P}\left\{ \exists n\in \mathbb{N}, \sum_{k=1}^n X_k \geq  3\sum_{k=1}^n Y_k+ l\log\frac{1}{\delta}\right\}
	\leq \delta,\nonumber
	\\  & \mathbb{P}\left\{  \exists n\in \mathbb{N},  \sum_{k=1}^n Y_k \geq 3\sum_{k=1}^n X_k + l\log\frac{1}{\delta}  \right\}    \leq \delta .\nonumber 
\end{align}
Lemma 14 (Fact): Let $X_1,X_2,\ldots, X_n$ be a sequence of independent random variables, with $X_i$ supported on $\mathcal{X}_i$. Let $f:\mathcal{X}_1\times \mathcal{X}_2\times\dots\times \mathcal{X}_n\to \mathbb{R}$ be a function such that: for any $i\in [n]$ and any $\{x_1,\ldots,x_n\}\in \mathcal{X}_1\times  \dots\times \mathcal{X}_n$, 
%
\begin{equation*}
	\sup_{x_i' \in \mathcal{X}_i}\big|f(x_1,\cdots,x_i,\cdots,x_n)-f(x_1,\cdots,x'_{i},\cdots,x_n) \big|\leq c
\end{equation*}
%
holds for some quantity $c>0$. It then holds that 
%
\begin{align}
	\mathbb{P}\Big\{ \big|f(X_1,X_2,\cdots, X_n) - \mathbb{E}\big[f(X_1,X_2,\cdots,X_n)\big] \big|\geq \varepsilon \Big\} 
	\leq 2\exp\left( -\frac{2\varepsilon^2}{nc^2}\right).\nonumber
\end{align}
Definition 2: Given a distribution $\mathcal{D}$ supported on $\mathcal{Z} \coloneqq \mathcal{X}\times \mathcal{Y}$ and a positive integer $n$, the Rademacher complexity is defined as
%
\begin{align}
	\mathsf{Rad}_{n}(\mathcal{D})
	\coloneqq 
	%\mathop{\mathbb{E}}_{\{z_i\}_{i=1}^n \overset{\small{\mathrm{i.i.d.}}}{\sim} \mathcal{D} }\left[ \mathop{\mathbb{E}}_{\{\sigma_i\}_{i=1}^n \overset{\small{\mathrm{i.i.d.}}}{\sim} \{\pm 1\} }  \left[ \sup_{h\in \mathcal{H}}\frac{1}{n}\sum_{i=1}^n \sigma_i\ell(h,z_i)\right] \right],
	\mathop{\mathbb{E}}_{\{z_i\}_{i=1}^n  }\left[ \mathop{\mathbb{E}}_{\{\sigma_i\}_{i=1}^n  }  \left[ \max_{h\in \mathcal{H}}\frac{1}{n}\sum_{i=1}^n \sigma_i\ell(h,z_i)\right] \right],
	\label{eq:defrad}
\end{align}
%
	 where $\{z_i\}_{i=1}^n$ are drawn independently from $\mathcal{D}$, and $ \{\sigma_i\}_{i=1}^n$ are i.i.d.~Rademacher random variables obeying $\mathbb{P}\{\sigma_i = 1\}=\mathbb{P}\{\sigma_i = -1\} = 1/2$ for each $1\leq i \leq n$.
Assumption 1: 	For each $n\geq 1$, there exists a quantity $C_n>0$ (known to the learner) such that
%
\begin{align}
	C_n \geq \sup_{w\in\Delta(k)}\mathsf{Rad}_{n}\big(\mathcal{D}(w)\big) .  \label{eq:radbb}
\end{align}
Definition 3: Given a collection of distributions $\mathcal{D}=\{\mathcal{D}_i\}_{i=1}^k$ and a set of positive integers $\{n_i\}_{i=1}^k$, the weighted (average) Rademacher complexity is defined as
%
\begin{align}
\widetilde{\mathsf{Rad}}_{\{n_{i}\}_{i=1}^{k}}\coloneqq\mathop{\mathbb{E}}\limits _{\{z_{i}^{j}\}_{j=1}^{n_{i}},\forall i\in[k]}\left[\mathop{\mathbb{E}}\limits _{\{\sigma_{i}^{j}\}_{j=1}^{n_{i}},\forall i\in[k]}\left[\frac{1}{\sum_{i=1}^{k}n_{i}}\max_{h\in\mathcal{H}}\sum_{i=1}^{k}\sum_{j=1}^{n_{i}}\sigma_{i}^{j}\ell\big(h,z_{i}^{j}\big)\right]\right],
\end{align}
%
where $\big \{\{z_i^j\}_{j=1}^{n_k} \big\}_{i=1}^k$ are independently generated with each $z_i^j$ drawn from $\mathcal{D}_i$, and $\big\{ \{\sigma_i^j\}_{j=1}^{n_i} \big\}_{i=1}^k $ are independent Rademacher random variables obeying $\mathbb{P}\{\sigma_i^j = 1\}=\mathbb{P}\{\sigma_i^j = -1\} = 1/2$. Throughout the rest of this paper, we shall often abbreviate $\widetilde{\mathsf{Rad}}_{\{n_{i}\}_{i=1}^{k}}=\widetilde{\mathsf{Rad}}_{\{n_{i}\}_{i=1}^{k}}(\mathcal{D})$.   
