Offline dataset: We assume access to an offline dataset $\{\Dc_h\}_{h=1}^H$. $\Dc_h$ consists of $M$ i.i.d. samples $(\spub, \{s_i,a_i,s'_i\}_{i\in[N]}, \{r_i\}_{i\in[N]})$ where $\spub\sim\rho, s_i\sim\sigma_{i,h}(\cdot|\spub), a_i\sim\nu_{i,h}(\cdot|\spub,s_i), s'_i\sim\Ps_{i,h}(\cdot|\spub,s_i,a_i)$ and $r_i\sim\Rs_{i,h}(\spub,\{s_i,a_i\}_{i\in[N]})$. Note that $\sigma_{i,h}$ may not be the local state visitation measure $d^{\nu_i}_h(\cdot|\spub)$. We also use $\sigma_{h}$ to denote $\prod_{i\in[N]}\sigma_{i,h}$.
General function approximation: We consider the general function approximation setting. This makes the algorithm applicable in potentially large or even infinite state space and action space. Suppose that we have function classes $\Rc=\{\Rc_i\}_{i=1}^N$ to approximate the reward function $\rs_{i,h}$ where $\Rc_i\subseteq\{r:\Spub\times\Ac\to[0,1]\}$ for all $i\in[N]$. In addition, we use function classes $\{\Pc_i\}_{i\in[N]}$ where $\Pc_i\subseteq\{P:\Spub\times\Sc_i\times\Ac_i\to\Delta_{\Sc_i}\}$ to approximate the transition model. We assume here that $\Rc_i$ and $\Pc_i$ are finite, but the analysis can be extended to infinite function classes naturally by replacing the cardinality of $\Rc_i$ and $\Pc_i$ with its covering or bracketing number. To simplify notation, we use $|\Rc|$ and $|\Pc|$ to denote $\max_{i\in[N]}|\Rc_i|$ and $\max_{i\in[N]}|\Pc_i|$.
Algorithm 1: \begin{algorithm}[ht]
\caption{Decentralized Regularized Actor-Critic (\texttt{DR-AC})}\label{alg:mdps}
\begin{algorithmic}[1]
\State Initialize $\pi^{1}_i$ to be the behavior policy $\nu_i$ for each agent $i$.

\State {\color{yxc} \textbf{/** Offline Reward \& Transition Learning **/}}
\State Compute for all $i\in[N],h\in[H]$
$$\hr_{i,h}=\argmin_{r\in\Rc_i} \!\!\! \sum_{(\spub,\bs,\ba,r_i)\in\Dc_h} \!\!\!\!\! (r(\spub,\bs,\ba)-r_i)^2, \; \hP_{i,h}=\argmax_{P\in\Pc_i} \!\!\! \sum_{(\spub,s_i,a_i,s'_i)\in\Dc_h} \!\!\!\!\! \log P(s'_i|\spub,s_i,a_i).$$
\For{$t=1,\ldots,T$}
\For{$i\in[N],h\in[H]$}

\State {\color{yxc} \textbf{/** Critic Update **/}}
\State Estimate the single-agent Q-function with the learned reward $\hr_i$ and transition $\hP_i$: 
$$\hQ^t_{i,h}(\spub,s_i,a_i)=\Eb_{(s_{j},a_{i)}\sim \hd^{\pi_j}_h(\cdot|\spub),\forall j \neq i}\left[\hQ^{\pi^t,\hr}_{i,h}(\spub,\bs,\ba)\right],\forall \spub\in\Spub,s_i\in\Sc_i,a_i\in\Ac_i.$$

\State {\color{yxc} \textbf{/** Actor Update **/}}
\State Run mirror descent for all $\spub\in\Spub,s\in\Sc_{i}$:
\begin{align}
\label{eq:mdp-update}
\pi^{t+1}_{i,h}(\spub,s)=\argmin_{p\in\Delta_{\Ac_{i,h}}} -\langle \hQ^t_{i,h}(\spub,s,\cdot), p\rangle + \lambda \chi^2(p,\nu_{i,h}(\spub,s)) + \frac{1}{\eta} D_{\spub,s,i}(p,\pi^t_{i,h}(\spub,s)).
\end{align}
\EndFor
\EndFor
\vspace{-10pt}
\State \textbf{Return:} the uniform mixture of $\left\{\prod_{i\in[N]}\pi^t_i\right\}_{t=1}^T$.
\end{algorithmic}
\end{algorithm}
