(ii)&=\Big|V^{\text{R}}_{\hpis,\hat{f}_n}(s)-V^{\text{R}}_{\pi^{*},f}(s)\Big|\nonumber \\&\leq\max_{s}\Big|V^{\text{R}}_{\hpis,\hat{f}_n}(s)-V^{\text{R}}_{\pi^{*},f}(s)\Big|\nonumber \\&\leq \frac{\gamma}{1-\gamma}\max_{s}\Big|\inf_{\mathrm{D}(p||P_{\hat{f}_{n}}(s,\hpis(s)))\leq \rho}\E_{s'\sim p}\Big[V^{\text{R}}_{\pi^{*},f}(s')\Big]-\inf_{\mathrm{D}(p||P_{f}(s,\hpis(s)))\leq \rho}\E_{s'\sim p}\Big[V^{\text{R}}_{\pi^{*},f}(s')\Big]\Big|.
\end{align}

A tight enough upper bound is

\begin{multline}
    \max_{s} \left|\inf_{KL(p||P_{\hat{f}_{n}}(s,\hat{\pi}_{n}(s)))\leq \rho}\E_{s'\sim p}\Big[V(s')\Big]-\inf_{KL(p||P_{f}(s,\hat{\pi}_{n}(s)))\leq \rho}\E_{s'\sim p}\Big[V(s')\Big]\right|\leq\\ \max_{s,a}2\tfrac{M}{\rho} e^{\frac{M}{\underline{\alpha}}}\max_{\alpha\in[\underline{\alpha},\overline{\alpha}]}\left|\E_{s'\sim P_{\hat{f}_{n}(s,a)}}[e^{\frac{-V(s')}{\alpha}}]-\E_{s'\sim P_{f}(s,a)}[e^{\frac{-V(s')}{\alpha}}]\right|.  \nonumber
\end{multline}

A tight enough upper bound is:

\begin{multline}
    \max_{s}\Big|\inf_{\chi^2(p||P_{\hat{f}_{n}}(s,\hat{\pi}_{n}(s)))\leq \rho}\E_{s'\sim p}\Big[V(s')\Big]-\inf_{\chi^2(p||P_{f}(s,\hat{\pi}_{n}(s)))\leq \rho}\E_{s'\sim p}\Big[V(s')\Big]\Big|\leq\\ \max_{s,a}c_{2}(\rho)\sup_{\eta\in [0,\frac{c_{2}(\rho)M}{c_{2}(\rho)-1}]}\{|\E_{\psa}[(-V(s')+\eta)_{+}^{2}]-\E_{\pnsa}[(-V(s')+\eta)_{+}^{2}]|^{\frac{1}{2}}\}
\end{multline}

A tight enough upper bound is:

\begin{multline}
    \max_{V\in \V}\max_{s,a}\sup_{\eta\in [0,\frac{c_{2}(\rho)M}{c_{2}(\rho)-1}]}\{|\E_{\psa}[(-V(s')+\eta)_{+}^{2}]-\E_{\pnsa}[(-V(s')+\eta)_{+}^{2}]|^{\frac{1}{2}}\}\leq \\
 \mathcal{O}\Bigg(\Big(\frac{c_{2}(\rho)M}{c_{2}(\rho)-1}\Big)\Big(\frac{ \beta_n(\delta)\sqrt{2ed^{2}\gamma_{nd}}}{\sigma\sqrt{n}}\Big)^{\frac{1}{2}}\Bigg),
\end{multline}

