Setup: We consider the finite-horizon Mean-Field Markov Decision Process (MF-MDP) specified by a tuple $M := (\mu_1,\cS,\cA,H,\mP_{T},\mP_{\textR})$. Here $\mu_1$ is the fixed initial distribution known to the learner, $\cS$ and $\cA$ are the state and action space.
Without loss of generality, we assume the state and action spaces are discrete but can be arbitrarily large.
We assume the state-action spaces are the same for each step $h$, i.e., $\cS_h=\cS$ and $\cA_h=\cA$ for all $h$. $\mP_{T}:=\{\mP_{T,h}\}_{h=1}^H$ and $r:=\{r_h\}_{h=1}^H$ are the transition and (normalized) deterministic reward function, with $\mP_{T,h}:\cS_h\times\cA_h\times\Delta(S_h)\rightarrow\Delta(S_{h+1})$ and $r_h:\cS_h\times\cA_h\times\Delta(S_h)\rightarrow [0,\frac{1}{H}]$. 
Without loss of generality, we assume that the reward function is known, but our techniques can be extended when it is unknown and a reward function class is available.
We use $M^*$ to denote the true model with transition function $\mP_{T^*}$.

We only consider non-stationary Markov policy $\pi:=\{\pi_1,...,\pi_H\}$ with $\pi_h:\cS_h\rightarrow\Delta(\cA_h),~\forall~h\in[H]$.
Starting from the initial state $s_1 \sim \mu_1$ until the fixed final state $s_{H+1}$ is reached, the trajectory is generated by $\forall h\in[H]$:
\begin{align*}
    & a_h \sim \pi_h(\cdot|s_h),~s_{h+1} \sim \mP_{T,h}(\cdot|s_h,a_h,\mu^\pi_{M,h}), \\
    & r_h \sim r_h(s_h,a_h,\mu^\pi_{M,h}),~\mu^\pi_{M,h+1} = \Gamma^\pi_{M,h}(\mu^\pi_{M,h}),\numberthis\label{eq:MF_formulation}
\end{align*}
where:
\begin{align*}
    \Gamma^\pi_{M,h}(\mu_h)(\cdot) := \SumInt_{s_h,a_h} \mu_h(s_h)\pi(a_h|s_h) \mP_{T,h}(\cdot|s_h,a_h,\mu_h)
\end{align*}
and we use $\mu^\pi_{M,h}$ to denote the density induced by $\pi$ under model $M$ and $\Gamma^\pi_{M,h}:\Delta(\cS_h)\rightarrow\Delta(\cS_{h+1})$ is an mapping from densities in step $h$ to step $h+1$ under $M$ and $\pi$.
We will use bold font $\vecmu := \{\mu_1,...,\mu_H\}$ to denote the collection of density for all time steps.
%
%
Besides, we denote $V^{\pi}_{M,h}(\cdot;\vecmu)$ to be the value functions at step $h$ if the agent deploys policy $\pi$ in model $M$ conditioning on $\vecmu$, defined by:
\begin{align}
    &V^{\pi}_{M,h}(s_h;\vecmu) := \EE\Big[\sum_{\ph=h}^H r_\ph(s_\ph,a_\ph,\mu_\ph) \Big| \nonumber\\
    &\qquad\qquad \forall \tldh \geq h,~a_\tldh \sim \pi_\tldh,~s_{\tldh+1}\sim \mP_{T,\tldh}(\cdot|s_\tldh,a_\tldh,\mu_\tldh)\Big].\label{eq:value_function}
    %
    %
\end{align}
%
We use $J_M(\pi;\vecmu) := \EE_{s_1\sim\mu_1}[V^{\pi}_{M,1}(s_1;\vecmu)]$ to denote the expected return of policy $\pi$ in model $M$ conditioning on $\vecmu$.
When the policy is specified, we use $\vecmu^\pi_M := \{\mu^\pi_{M,1},...,\mu^\pi_{M,H}\}$ to denote the collection of mean fields w.r.t. $\pi$. 
We will omit $\vecmu$ and use $J_M(\pi)$ in shorthand when $\vecmu = \vecmu^\pi_M$.
For  simplicity, we use 
$$
\EE_{\pi,M|\vecmu}[\cdot] := \EE\left[\cdot\Big|\substack{s_1\sim\mu_1 \\ \forall h\geq 1,\quad a_h \sim \pi_h(\cdot|s_h)\\ s_{h+1}\sim\mP_{T,h}(\cdot|s_h,a_h,\mu_h)}\right]
$$ 
as a shortnote of the expectation over trajectories induced by $\pi$ under transition $\mP_{T,h}(\cdot|\cdot,\cdot,\mu_h)$, and we omit the conditional density $\vecmu$ if $\vecmu = \vecmu^\pi_M$.
As examples, $V^\pi_{M,h}(s_h;\vecmu) = \EE_{\pi,M|\vecmu}[\sum_{h'=h}^H r(s_\ph,a_\ph,\mu_\ph)|s_h]$ and $J_M(\pi) = \EE_{\pi,M}[\sum_{h=1}^H r(s_\ph,a_\ph,\mu^\pi_{M,\ph})]$.

%
Given a measure space $(\Omega, \cF)$ and two probability measures $P$ and $Q$ defined on $(\Omega, \cF)$, we denote $\matDTV(P,Q)$ (or $\|P - Q\|_\TV$)$ := \sup_{A \in \cF} |P(A) - Q(A)|$ as the total variation distance, and denote $\mH(P,Q) := \sqrt{1 - \SumInt_x \sqrt{P(x)Q(x)}}$ as the Hellinger distance. In general, when $\Omega$ is countable, we have $\sqrt{2} \mH(P,Q) \geq \matDTV(P,Q) = \frac{1}{2} \|P-Q\|_1$, where $\|\cdot\|_1$ is the $l_1$-distance.
Mean-field control: In MFC, similar to single-agent RL, we are interested in the optimality gap 
$
\cE_{\Opt}(\pi):= \max_\tpi J_{M^*}(\tpi;\vecmu^\tpi_{M^*}) - J_{M^*}(\pi;\vecmu^{\pi}_{M^*}),
$ 
and aim to find a policy $\hat\pi^*_\Opt$ to approximately minimize it:
\begin{equation}
    \cE_{\Opt}(\hat\pi^*_\Opt)\leq \epsilon.\label{eq:objective_MFC}
\end{equation}
Mean-field game: In MFG, we instead want to find a Nash Equilibrium (NE) policy s.t., when all the agents follow that same policy, no agent tends to deviate from it for better policy value.
We denote $\Delta_M(\tpi, \pi) := J_M(\tpi;\vecmu^\pi_M) - J_M(\pi;\vecmu^\pi_M)$ given a model $M$, and denote 
$
\cE_\NE(\pi) := \max_\tpi \Delta_{M^*}(\tpi, \pi),
$
which is also known as the exploitability.
The NE in $M^*$ is defined to be the policy $\pi_{\NE}^*$ satisfying $\cE_\NE(\pi_{\NE}^*) = 0$.
In MFG, the objective is to find an approximate NE $\hat\pi^*_\NE$ such that:
\begin{equation}
    \cE_\NE(\hat\pi_{\NE}^*) \leq \epsilon.\label{eq:objective_MFG}
\end{equation}

We consider the general function approximation setting, where the learner has access to a model class $\cM$ with finite cardinality ($|\cM| < +\infty$)
Assumption A: $M^* \in \cM$.
Assumption B: For arbitrary $h\in[H],s_h\in\cS,a_h\in\cA$ and arbitrary valid density $\mu_h,\mu_h'\in\Delta(\cS)$, and arbitrary model $M:=(\mP_T,r) \in \cM$, we have:

    \begin{align}
        %
        &\|\mP_{T,h}(\cdot|s_h,a_h,\mu_h) - \mP_{T,h}(\cdot|s_h,a_h,\mu_h')\|_\TV \nonumber\\
        &\qquad\qquad\qquad\qquad\qquad\qquad \leq L_T \|\mu_h-\mu_h'\|_\TV, \label{eq:Lip_model_H}\\
        %
        &\|r_h(s_h,a_h,\mu_h) - r_h(s_h,a_h,\mu_h')\|_\TV \nonumber\\
        &\qquad\qquad\qquad\qquad\qquad\qquad \leq L_r \|\mu_h-\mu_h'\|_\TV. \label{eq:Lip_rew_l1}
        %
    \end{align}
Definition 3.3: We assume the environment consists of an extremely large number of agents and a central controller (our algorithm/learner), and there is a representative agent $\texttt{Agent}$, whose observation we can receive. 
The central controller can compute an arbitrary policy tuple ($\tilde\pi$, $\pi$) (here $\pi$ and $\tpi$ are not necessarily the same), distribute $\tilde\pi$ to $\texttt{Agent}$ but $\pi$ to the others, and receive the trajectory of $\texttt{Agent}$ following $\tpi$ under $\mP_{T^*,h}(\cdot|\cdot,\cdot,\mu^\pi_h)$ and $\mP_{r,h}(\cdot|\cdot,\cdot,\mu^\pi_h)$.
Definition 4.1: Denote $\cX:=\cS\times\cA\times\Delta(\cS)$ to be the joint space of state, action, and state density. 
    Let $\matD:\Delta(\cS)\times\Delta(\cS)\rightarrow [0,C]$ be a distribution distance measure bounded by some constant $C$.
    Given a function class $\cF\subset\{f:\cX\rightarrow\Delta(\cS)\}$, a fixed $\alpha \geq 1$ and a sequence of data points $x_1,x_2,...,x_n \in \cX$, we say $x$ is $\alpha$-weakly-$\epsilon$-independent of $x_1,...,x_n$ w.r.t. $\cF$ and $\matD$ if there exists $f_1,f_2\in\cF$ such that $\sum_{i=1}^{n} \matD^2(f_1, f_2)(x_i) \leq \epsilon^2$ but $\matD(f_1, f_2)(x) > \alpha\epsilon$.
Definition 4.2: We use $\dimE_\alpha(\cF,\matD,\epsilon)$ to denote the longest sequence $\{x_i\}_{i=1}^n \in \cX$, such that for some $\epsilon' \geq \epsilon$, $x_{i}$ is $\alpha$-weakly-$\epsilon'$-independent of $\{x_1,...,x_{i-1}\}$ for all $i\in[n]$ w.r.t. $\cF$ and $\matD$.
Definition 4.3: Given a model class $\cM$, $\alpha \geq 1$ and $\epsilon > 0$, the Model-Based Eluder Dimension in MFRL (abbr. MF-MBED) of $\cM$ is defined as:
    \begin{align*}
        \textstyle \dimE_\alpha&(\cM,\epsilon) := \\
        &\max_{h\in[H]} \min_{\matD\in\{\matDTV,\mH\}} \dimE_\alpha(\cM_h,\matD,\epsilon).\numberthis\label{eq:MB_ED_MFRL}
    \end{align*}
Algorithm 1: \begin{algorithm}
    \textbf{Input}: Model function class $\cM$; $\epsilon,\delta,K$.\\
    %
    \textbf{Initialize}: Randomly pick $\pi^1$ and $\tpi^1$; $\cZ^k \gets \{\},~\forall k\in[K]$.\\
    \For{$k=1,2,...,K$}{
        \For{$h=1,...,H$}{\label{line:DS}
            Sample $z^k_h := \{s_h^k, a_h^k, s_{h+1}'^k\}$ with $(\pi^k,\pi^k)$; $\cZ^k \gets \cZ^k \cup z^k_h$.\\
            \lIf{\blue{\MFG}}{
                Sample $\tz_h^k := \{\ts_h^k, \ta_h^k, \ts_{h+1}'^k\}$ with ($\tpi^k$, $\pi^k$); $\cZ^k \gets \cZ^k \cup \tz_h^k$
            }
        }\label{line:DE}
        For each $M\in\cM$, define: \label{line:SS}
            \begin{align*}
                l_{\MLE}^{k}(M) :=& \sum_{i=1}^k\sum_{h=1}^H \log  \mP_{T,h}(s_{h+1}'^i|s_h^i,a_h^i,\mu^{\pi^{i}}_{M,h}) \\
                &+ \underbrace{\sum_{i=1}^k\sum_{h=1}^H\log  \mP_{T,h}(\ts_{h+1}'^i|\ts_h^i,\ta_h^i,\mu^{\pi^{i}}_{M,h})}_{\text{\blue{MFG}~only}}.
            \end{align*}
        \label{line:MLE_loss}\\
        %
        %
            $
            \hat\cM^k \gets \{M \in \cM |
            l_{\MLE}^k(M)\geq \max_{M\in\cM} l_{\MLE}^k(M) - \log\frac{2|\cM|KH}{\delta}\},
            $\label{line:confidence_set}\\
        %
        \lIf{\red{\MFC}}{
            $\pi^{k+1}, M^{k+1} \gets \arg\max_{\pi, M\in\hat\cM^k} J_{M}(\pi;\vecmu^\pi_M)$
        }
        \If{\blue{\MFG}}{
            Randomly pick $M^{k+1}$ from $\hat\cM^k$; \\
            Find a NE of $M^{k+1}$ denoted as $\pi^{k+1}$.\\
            $\tpi^{k+1}, \tM^{k+1} \gets \arg\max_{\tpi; M\in\hat\cM^k} \Delta_{M}(\tpi, \pi^{k+1})$.
        }\label{line:SE}
    }
    \lIf{\red{\MFC}}{
        \Return $\hat\pi^*_{\Opt} \gets \text{Regret2PAC}(\{\pi^{k+1}\}_{k=1}^K, \epsilon, \delta)$
    }
    \lIf{\blue{\MFG}}{
        \Return $\hat\pi^*_\NE \gets \pi^{k^*_\NE}$ with $k^*_\NE \gets \min_{k\in[K]} \Delta_{\tM^{k+1}}(\tpi^{k+1}, \pi^{k+1})$
    }
    \caption{A General Maximal Likelihood Estimation-Based Algorithm for Mean-Field RL}\label{alg:MLE_MB_Alg}
\end{algorithm}
Assumption C: For arbitrary $h$, and arbitrary valid density $\mu_h,\mu_h' \in \Delta(\cS)$, and arbitrary model $M:=(\mP_T,r) \in \cM$, there exists $L_\Gamma < 1$, such that,
    \begin{align*}
        \forall \pi,~\|\Gamma^\pi_{M,h}(\mu_h) - \Gamma^\pi_{M,h}(\mu_h')\|_{\TV} \leq L_\Gamma\|\mu_h - \mu_h'\|_{\TV}.
    \end{align*}
Algorithm 2: \begin{algorithm}
    \textbf{Input}: Policy sequence $\pi^1,...,\pi^K$; Accuracy level $\epsilon$; Confidence level $\delta$.\\
    $N \gets \lceil \log_\frac{3}{2}\frac{1}{\delta}\rceil$.\\
    Randomly select $N$ policies from $\pi^1,...,\pi^K$, denoted as $\pi^{k_1},...\pi^{k_N}$.\\
    \For{$n\in[N]$}{
        Sample $\frac{16}{\epsilon^2}\log\frac{2N}{\delta}$ trajectories by deploying $\pi^{k_n}$.\\
        Compute empirical estimation $\hat{J}_{M^*}(\pi^{k_n})$ by averaging the return in trajectories.
    }
    \Return $\pi := \pi^{k_{n^*}}$ with $n^* \gets \arg\max_{n\in[N]}\hat{J}_{M^*}(\pi^{k_n})$.
    \caption{Regret to PAC Conversion}\label{alg:Regret2PAC}
\end{algorithm}

