Notations: For two positive-valued functions $f(x)$ and $g(x)$, we write $f(x)\lesssim g(x)$ or $f(x)\gtrsim g(x)$
if there exists a constant $c>0$ such that $f(x) \le cg(x)$ or $f(x) \ge cg(x)$ for every $x$, respectively. 
We write $f(x) \eqsim g(x) $ if $f(x) \lesssim g(x) \lesssim f(x)$.
We use the standard big-O notation. 
For two vectors $\uB$ and $\vB$ in a Hilbert space, we denote their inner product by $\la\uB, \vB\ra$ or equivalently, $\uB^\top \vB$.
For two matrices $\AB$ and $\BB$ of appropriate dimension, we define their inner product as $\langle \AB, \BB \rangle := \tr(\AB^\top \BB)$.
For a positive semi-definite (PSD) matrix $\AB$ and a vector $\vB$ of appropriate dimension, we write $\|\vB\|_{\AB}^2 := \vB^\top \AB \vB$. In particular, we write $\|\vB \| := \|\vB \|_\IB$.
For a positive integer $n$, we write $[n]:=\{1,\dots,n\}$.

Let $(\xB,y)\in\Hbb\otimes \{\pm 1\}$ be a pair of features and the corresponding binary label sampled from an unknown population distribution.
Here $\Hbb$ is a finite or countably infinite dimensional Hilbert space.  
For a parameter $\wB\in\Hbb$, define its population \emph{logistic risk} as
\begin{align*}
    \risk(\wB):= \Ebb \ell(y \xB^\top \wB),\ \text{where} \ \ell(t) := \ln(1+e^{-t}),
\end{align*}
and define its population \emph{zero-one error} as
\begin{align*}
    \error(\wB):= \Ebb \ind{y\xB^\top \wB \le 0} 
    = \Pr(y\xB^\top \wB \le 0),
\end{align*}
where the expectation is over the population distribution of $(\xB,y)$.
It is worth noting that, different from the logistic risk $\risk(\wB)$, the zero-one error $\error(\wB)$ is insensitive to the parameter norm.
Moreover, we measure the \emph{calibration error} of a parameter $\wB\in\Hbb$ by
\begin{align*}
    \calibration(\wB):= \Ebb \big|p(\wB;\xB) - \Pr(y=1|\xB)\big|^2,
\end{align*}
where $p(\wB;\xB)$ is a naturally induced conditional probability given by 
\begin{align*}
    p(\wB;\xB) := \frac{1}{1+\exp(-\xB^\top\wB)}.
\end{align*}

We say an estimator $\hat \wB$ is \emph{consistent} (for classification) if it attains the Bayes zero-one error asymptotically, that is, $\error(\hat \wB) - \min \error \to 0$.
We say an estimator $\hat\wB$ is \emph{calibrated} if its induced conditional probability predicts the true one asymptotically, that is, $\calibration(\hat\wB) \to 0$.
Assumption 1: Let $\SigmaB \in \Hbb^{\otimes 2}$ be positive semi-definite (PSD) and $\tr(\SigmaB) < \infty$. Let $\wB^*\in\Hbb$ be such that $\|\wB^*\|_{\SigmaB} < \infty$.
Assume that $(\xB, y)\in \Hbb \otimes \{\pm 1\}$ is given by
\begin{align*}
\xB\sim \Ncal(0,\SigmaB),\quad \Pr(y | \xB) = \frac{1}{1+\exp(-y\xB^\top \wB^*)}.
\end{align*}
More notations: Let $(\lambda_i)_{i\ge 1}$ be the eigenvalues of the data covariance $\SigmaB$, sorted in non-increasing order. Let $\uB_i$ be the eigenvector of $\SigmaB$ corresponding to $\lambda_i$.
Let $\big(\pi(i)\big)_{i\ge 1}$ be resorted indexes
such that $\lambda_{\pi(i)}\big(\uB_{\pi(i)}^\top \wB^*\big)^2$ is non-increasing as a function of $i$. Define 
\[
\wB^*_{0:k} := \sum_{i\le k} \uB_{\pi(i)}\uB_{\pi(i)}^\top \wB^*,\quad 
\wB^*_{k:\infty} := \sum_{i> k} \uB_{\pi(i)}\uB_{\pi(i)}^\top \wB^*.
\]
It is clear that $\|\wB^*\|_{\SigmaB} < \infty$ implies that $\big\|\wB^*_{k:\infty}\big\|_{\SigmaB} = o(1)$ as $k$ increases.
Assumption 2: Assume that $\rank\{\xB_i: i \in \Scal_+\} = \rank\{\xB_i: i \in [n]\}$.

Setup: We also introduce a couple of notation to be used throughout. 
\begin{equation}
%f^* = f(\bm{x}^*),\qquad 
f_i = f(\bm{x}_i)
\qquad \text{and} \qquad 
\bm{g}_i =  \nabla f(\bm{x}_i)
\label{eq:defn-fi-gi}
\end{equation}
%
for each iteration $i$. 
For a given stepsize schedule $\{\alpha_t\}_{t\geq 1}$, we set
%
\begin{align}
A_n \coloneqq \sum_{i=1}^{n-1}\alpha_{i}
\qquad \text{and}\qquad C_n \coloneqq  \frac{A_n (A_n+1)}{2}
\label{eq:defn-An-Cn}
\end{align}
%
for any integer $n\geq 2$, 
where in the notation of $A_n$ and $C_n$, we suppress the dependence on $\{\alpha_t\}_{t\geq 1}$ as long as it is clear from the context.   
Additionally, for an infinite sequence $\bm{r}=[r_j]_{j= 1}^{\infty}$, 
we define 
%
\begin{align}
A_n(\bm{r})= \sum_{i=1}^{n-1}r_i
\qquad \text{and}\qquad 
C_n(\bm{r})= \frac{A_n(\bm{r})(A_n(\bm{r})+1)}{2}. 
%$\overline{A}(\bm{s})=\overline{A}$
\label{eq:defn-An-Cn-inf}
\end{align}
%
In addition, we often use $\bm{\alpha}_{\ell:k}$ to indicate the stepsize subsequence $[\alpha_{\ell},\dots,\alpha_k]^{\top}$, and let $\alpha_i(\bm{s})$ denote the $i$-th stepsize in a stepsize sequence $\bm{s}$. 
Definition 2: A stepsize schedule $\bm{\alpha}_{1:k-1}=[\alpha_1,\dots,\alpha_{k-1}]\in \mathbb{R}_+^{k-1}$ is said to be primitive if
%
\begin{subequations}
\begin{align}&
A_{k}(f_k-f^*) + C_k \|\bm{g}_k\|^2 +\frac{1}{2}\|\bm{x}_k-\bm{x}^*\|^2
\notag\\ &\quad\leq \frac{1}{2}\|\bm{x}_1-\bm{x}^*\|^2 +\sum_{i=1}^{k-1} \alpha_i \left(f_i - f^* -\langle \bm{g}_i, \bm{x}_i-\bm{x}^*\rangle + \frac{1}{2}\|\bm{g}_i\|^2 \right)\label{eq:defn-primitive-1}
\\  &\quad \leq \frac{1}{2}\|\bm{x}_1-\bm{x}^*\|^2.
\label{eq:defn-primitive}
\end{align}
\end{subequations}

If we have available a collection of basic primitive sequences --- denoted by $\{\bm{s}_i\}_{i\geq 1}$, then we can concatenate them as follows: 
%
\begin{subequations}
\label{eq:defn-s-hat}
\begin{align}
\widehat{\bm{s}}_{0} & =[\,],\\
\widehat{\bm{s}}_{i} & \leftarrow \mathsf{concat}(\widehat{\bm{s}}_{i-1},\bm{s}_{i}),\qquad i=1,2,\dots\\
\widehat{\bm{s}} & \leftarrow\lim_{i\rightarrow\infty}\widehat{\bm{s}}_{i}.
\end{align}
\end{subequations}
Definition 5: Let $\overline{\bm{s}}_0=[\,]$ be the null sequence, and set $\overline{\bm{s}}_{i} = \mathsf{concat}(\overline{\bm{s}}_{i-1},\overline{\bm{s}}_{i-1})$ for each $i\geq 1$. Then 
$\overline{\bm{s}}_i$ is said to be the $i$-th order silver stepsize schedule, 
with the (limiting) silver stepsize schedule given by $\overline{\bm{s}}\coloneqq \lim_{i\to\infty}\overline{\bm{s}}_i$. 
Construction 1: Armed with the silver stepsize schedules $\{\overline{\bm{s}}_j\}_{j\geq 0}$  introduced in Definition 5 --- which serve as basic primitive sequences --- 
we can readily present the proposed stepsize schedule.


Choose some positive quantity $c\geq 1$. While we shall keep $c$ as a general quantity throughout most of the proof, it will be taken to be $c=\log_2\rho$ where $\rho = 1 + \sqrt{2}$ at the last step of our proof of the main theorems.  
%let $k_0=M_0=0$, 
Also, set
%
\begin{equation}
k_0=M_0=0,\qquad 
k_i = \left\lfloor2\cdot 2^{c i} \right\rfloor,
\qquad \text{and}\qquad 
M_i = \sum_{j=1}^i k_i,
\qquad i=1,2,\dots
\end{equation}
%
%for $i\geq 1$, where $c=7$. 
%In particular, we define $k_0 = M_0 =0$. 
%
With these parameters in place, 
our construction proceeds as follows:
%
\begin{itemize}
    \item For each $j\geq 1$, set $\bm{s}_i=\overline{\bm{s}}_j$ for every $i$ obeying $M_{j-1}<i \leq M_{j} $, 
    where $\overline{\bm{s}}_j$ denotes the $j$-th order silver stepsize schedule in Definition 5. 
    In other words,  we repeat $\overline{\bm{s}}_j$ for $k_j$ times for each $j\geq 1$, with $k_j$ exponentially increasing in $j$.

    \item Generate the infinite stepsize sequence $\widehat{\bm{s}}$ through the concatenation procedure:

\begin{subequations}
\label{eq:defn-s-hat}
\begin{align}
\widehat{\bm{s}}_{0} & =[\,],\\
\widehat{\bm{s}}_{i} & \leftarrow \mathsf{concat}(\widehat{\bm{s}}_{i-1},\bm{s}_{i}),\qquad i=1,2,\dots\\
\widehat{\bm{s}} & \leftarrow\lim_{i\rightarrow\infty}\widehat{\bm{s}}_{i}.
\end{align}
\end{subequations}

\end{itemize}
Lemma 6: For each $i\geq 1$, $\overline{\bm{s}}_{i}$ is a primitive sequence with length $2^{i}-1$. Moreover, it holds that
\begin{equation}
%\sum_{j=1}^{2^i-1}\alpha_j(\overline{\bm{s}}_i) 
\bm{1}^{\top} \overline{\bm{s}}_i = \rho^i-1,
\qquad i=0,1,\dots
\end{equation}
Lemma 8: Suppose $\bm{s}=\bm{\alpha}_{1:k-1}$ is a primitive stepsize schedule. Then for any fixed $\bm{x}_0$ with gradient $\bm{g}_0$, it holds that
\begin{align}
&  A_{k} (f_{k}-f_0) + \frac{1}{2}\|\bm{x}_{k}-\bm{x}_0\|^2 + C_{k} \|\bm{g}_{k}\|^2\leq \frac{1}{2}\|\bm{x}_1-\bm{x}_0\|^2 + \sum_{i=1}^{k-1}\alpha_i \langle\bm{g}_i, \bm{g}_0\rangle - \frac{A_{k}}{2}\|\bm{g}_0\|^2;\label{eq:rs1}
\end{align}

