    \item If $\frac{\rd}{\rd s}\big|_{s=0}\LL(\bar{\mu}_s)=0$ for all $\bR\in\BB_1(k)$ above, then $\LL(\mu)\geq \frac{\underline{r}}{2}$ and $\frac{\rd^2}{\rd s^2}|_{s=0}\LL(\bar{\mu}_s)\leq -\frac{4}{kR_1^2}\LL(\mu)^2$ for some $\bR\in\BB_1(k)$.\label{item:secondorder}
