Problem introduction: Setting the stage, 
imagine that we are interested in a collection of $k$ unknown data distributions $\mathcal{D}=\{\mathcal{D}_i\}_{i=1}^k$ supported on $\mathcal{X}\times \mathcal{Y}$,    
where $\mathcal{X}$ (resp.~$\mathcal{Y}$) stands for the instance (resp.~label) space. 
Given a hypothesis class $\mathcal{H}$ and a prescribed loss function\footnote{For example, for each hypothesis $h\in \mathcal{H}$ and each datapoint $(x,y)\in \mathcal{X}\times \mathcal{Y}$, we employ $\ell(h,(x,y))$ to measure the risk of using hypothesis $h$ to predict $y$ based on $x$.} $\ell:\mathcal{H}\times\mathcal{X}\times \mathcal{Y} \to [-1,1]$, 
we are asked to identify a (possibly randomized) hypothesis $\widehat{h}$  
achieving near-optimal {\em worst-case} loss across these data distributions, namely
 \begin{align}
	 \max_{1\leq i\leq k} \mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i,\widehat{h}}\big[\ell\big(\widehat{h},(x,y)\big)\big] \leq  \min_{h\in \mathcal{H}}\max_{1\leq i\leq k}\mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i}\big[\ell\big(h,(x,y)\big)\big] + \varepsilon \label{eq:defproblem}
 \end{align}
with $\varepsilon\in (0,1]$ a target accuracy level. 
In light of the unknown nature of these data distributions, 
the learning process is often coupled with data collection, allowing the learner to sample from $\{\mathcal{D}_i\}_{i=1}^k$. 
The performance of a learning algorithm is then gauged by its sample complexity --- the number of samples required to fulfil \eqref{eq:defproblem}.

Given a target accuracy level $\varepsilon\in (0,1)$, our objective is to identify a (randomized) hypothesis, represented by $h_{\pi}$ with $\pi\in \Delta(\mathcal{H})$, such that 
%
\begin{align}
	\max_{1\leq i\leq k} \mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i, h\sim \pi}\big[ \ell \big(h, (x,y) \big) \big]
	%\sum_{h\in \mathcal{H}} \pi_h  \mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i}\big[\ell \big(h,(x,y) \big) \big]  
	\leq  
	\min_{h\in \mathcal{H}}\max_{1\leq i\leq k}\mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i}\big[\ell \big(h,(x,y) \big) \big] + \varepsilon.
	\label{eq:goal-overall}
\end{align}
Algorithms prelim: Specifically, for any distribution $w=[w_i]_{1\leq i\leq k}\in \Delta(k)$ and any hypothesis $h\in \mathcal{H}$, 
the risk over the mixture $\sum_{i\in[k]} w_i\mathcal{D}_i$  of data distributions is denoted by: 
%
\begin{subequations}
\begin{equation}
	L(h,w) \coloneqq \sum_{i=1}^k w_i \mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i}\big[\ell \big(h,(x,y)\big)\big]; 
	\label{defn:L}
\end{equation}
%
similarly, the risk of a randomized hypothesis $h_{\pi}$ (associated with $\pi\in \Delta(\mathcal{H})$) over  $\sum_{i\in[k]} w_i\mathcal{D}_i$ is given by
%
\begin{equation}
	L (h_{\pi}, w) \coloneqq \sum_{i=1}^k w_i \mathop{\mathbb{E}}\limits_{(x,y)\sim \mathcal{D}_i,h\sim \pi}\big[\ell \big(h_{\pi},(x,y)\big)\big]
	= \mathop{\mathbb{E}}\limits_{h\sim \pi}  \big[ L(h,w) \big].
\end{equation}
\end{subequations}
Algorithm 1: \begin{algorithm}[]
\small
	\DontPrintSemicolon
	\caption{Hedge for multi-distribution learning on VC classes ($\mathtt{MDL}\text{-}\mathtt{Hedge}\text{-}\mathtt{VC}$)\label{alg:main1}}
%
	\textbf{input:} $k$ data distributions $\{\mathcal{D}_1,\mathcal{D}_2,\ldots,\mathcal{D}_k\}$,  hypothesis class $\mathcal{H}$, target accuracy level $\varepsilon$, target success rate $1-\delta$. \\
\textbf{hyper-parameters:} stepsize $\eta=\frac{1}{100}\varepsilon$, number of rounds $T= \frac{20000\log\left(\frac{k}{\delta}\right)}{\varepsilon^2}$, 
	auxiliary accuracy level $\varepsilon_1=\frac{1}{100}\varepsilon$, %$\tilde{T}_1 =\frac{400(k\log(\frac{k}{\varepsilon_1})+d\log(\frac{kd}{\varepsilon_1})+\log(\frac{dk}{\delta\varepsilon_1})}{\varepsilon_1}$, 
	auxiliary sub-sample-size $\Tone \coloneqq \frac{4000\left(k\log(k/\varepsilon_1) +d\log(kd/\varepsilon_1)+\log(1/\delta)\right)}{\varepsilon_1^2}.$  \label{line:hyper-pars}\\
	\textbf{initialization:} 
	%$w^1 = [1/k,1/k,\ldots,1/k]^{\top}$, 
	for all $i \in [k]$, set $W^1_i=1$, $\widehat{w}^0_i=0$ and $n_i^0=0$;  
	%$\widehat{w}^0=[0,\ldots,0]^{\top}$, 
	$\weighteddata=\emptyset$.  \\
%  \emph{ \textcolor{red}{option for learning a Rademacher class:}}      draw $12\log(2k)$ samples from $D_i$ for each $i$, and add these samples to $\weighteddata$.\label{line:rad}  \\
	%$n^0= \{n_i^0\}_{i=1}^k$ with 
	%$n_i^0=0$ for all $i\in [k]$. \\
	\For{$t=1,2,\ldots, T$}{
		set $w^t= [w^t_i]_{1\leq i\leq k}$  and $\widehat{w}^t= [\widehat{w}^t_i]_{1\leq i\leq k}$,  
		with $w^t_i \leftarrow \frac{W^t_i}{\sum_{j}W^t_j}$ and $\widehat{w}^t_i \leftarrow \widehat{w}^{t-1}_i$ for all $i\in [k]$. 
		\label{line:wt-update-Wt}\\
		%
		%{\color{blue}\tcc{construct estimators to learn the near-optimal response.}}
		%
		{\color{blue}\tcc{recompute $\widehat{w}^t$ \& draw new samples for $\weighteddata$ only if $w^t$ changes sufficiently.}}
		\If{there exists $j\in [k]$ such that $w_j^t \geq 2\widehat{w}_j^{t-1}$ \label{line:a1}}{ 
			$\widehat{w}^t_i \leftarrow  \max\{w^{t}_i, \widehat{w}^{t-1}_i\}$ for all $i\in [k]$; \\
			\For{$i=1,\ldots,k$}{  $n_i^t \leftarrow \left\lceil \Tone\widehat{w}^t_i \right\rceil$; \label{line:nit} \\
			draw $n_i^t - n_i^{t-1}$ independent samples from $\mathcal{D}_i$, and add these samples to $\weighteddata$.\label{line:sample1}
			}
		}
		{\color{blue}\tcc{estimate the near-optimal hypothesis for weighted data distributions.}}
		compute $h^t\leftarrow \arg\min_{h\in \mathcal{H}} \widehat{L}^t(h,w^t)$, where \label{line:compute-ht}
		%
		\begin{align}
			\widehat{L}^t(h,w^t) \coloneqq \sum_{i=1}^k \frac{w^t_i}{n_i^t}\cdot \sum_{j=1}^{n_i^t}\ell\big(h,(x_{i,j},y_{i,j})\big)\label{eq:e1}
		\end{align}
		%
		with $(x_{i,j},y_{i,j})$ being the $j$-th datapoint from $\mathcal{D}_i$ in $\weighteddata$. \label{line:a2}
  \\
		{\color{blue}\tcc{estimate the loss vector and execute weighted updates.}}
		%
		$\overline{w}^t_i \leftarrow \max_{1\leq \tau \leq t}w^{\tau}_i$ for all $i \in [k]$. \\
		\For{$i=1,\ldots, k$}{ 
		draw $ \lceil k\overline{w}^t_i \rceil$ independent samples --- denoted by $\big\{(x^t_{i,j},y^t_{i,j})\big\}_{j=1}^{\lceil k\overline{w}_i^t\rceil}$ --- from $\mathcal{D}_i$, and set \label{line:updateS} 
		$$
			\widehat{r}^t_i  =\frac{1}{\lceil k\overline{w}^t_i\rceil}\sum_{j=1}^{\lceil k\overline{w}^t_i \rceil} \ell\big(h^t,(x_{i,j}^t,y_{i,j}^t) \big); 
		$$

		update the weight as $W^{t+1}_i = W^t_i  \exp(\eta \widehat{r}_i^t)$. \label{line:updateS11} {\color{blue}\tcp{Hedge updates.}}
		}
	}
	\textbf{output:}  a randomized hypothesis $h^{\mathsf{final}}$ uniformly distributed over $ \{h^t\}_{t=1}^T$.
