Definition 1: For any $p,x>0$ and $i\in [k]$, we say that $(t_1,t_2)$ is a $(p,q,x)$-\emph{segment}  if there exists a subset $\mathcal{I}\subseteq [k]$  such that 
%
\begin{itemize}
	\item[$\mathrm{(i)}$] $\sum_{ i\in \mathcal{I}}w^{t_1}_{i}\in \left[p/2 ,p\right]$, 
	\item[$\mathrm{(ii)}$] $\sum_{i\in \mathcal{I}}w^{t_2}_i \geq p \exp(x)$,  
	\item[$\mathrm{(iii)}$] $\sum_{i\in \mathcal{I}}w_i^{t}\geq  q$ for any $t_1\leq t\leq t_2$. 
\end{itemize}
%
We shall refer to $t_1$ as the starting point and $t_2$ as the end point, and call $\mathcal{I}$ the associated index set. Moreover,  two segments $(s_1,e_1)$ and $(s_2,e_2)$ are said to be disjoint if $s_1<e_1 \leq s_2<e_2$ or $s_2<e_2\leq s_1<e_1$. 
Algorithm 4: \begin{algorithm}
	\DontPrintSemicolon
	\caption{Hedge for multi-loss multi-distribution learning ($\mathtt{MLMDL}\text{-}\mathtt{Hedge}\text{-}\mathtt{VC}$)\label{alg:obj}}
%
	\textbf{input:} $k$ data distributions $\{\mathcal{D}_i\}_{i=1}^k$, loss function class  $\mathcal{L}=\{\ell^j\}_{j=1}^R$, hypothesis class $\mathcal{H}$, target accuracy level $\varepsilon$, target success rate $1-\delta$. \\
\textbf{hyper-parameters:} stepsize $\eta=\frac{1}{100}\varepsilon$, number of rounds $T= \frac{20000\log\left(\frac{kR}{\delta\varepsilon}\right)}{\varepsilon^2}$, 
	auxiliary accuracy level $\varepsilon_1=\frac{1}{100}\varepsilon$,
	auxiliary sub-sample-size $T_1 := 
 \frac{40000\left(k\log ( \frac{kR}{\varepsilon_1} )+d\log\big( (\frac{kd}{\varepsilon_1} )+\log(\frac{1}{\delta}) \big) \right)}{\varepsilon_1^2}.$ \\
	\textbf{initialization:} 
	for all $i \in [k]$ and $\ell\in \mathcal{L}$, set $U^1_{i,\ell}=1$, $\widehat{w}^0_{i}=0$ and $n_i^0=0$;  
	$\weighteddata=\emptyset$.  \\
	\For{$t=1,2,\ldots, T$}{
		set $u^t= [u^t_{i,\ell}]_{1\leq i\leq k,\ell \in \mathcal{L}}$
		with $u^t_{i,\ell} \leftarrow \frac{U^t_{i,\ell}}{\sum_{i'\in [k],\ell'\in \mathcal{L}}U^t_{i',\ell'}}$ .\\
  set  $\widehat{w}^t= [\widehat{w}^t_{i}]_{1\leq i\leq k}$ with  $\widehat{w}^t_{i} \leftarrow \widehat{w}^{t-1}_{i}$ for all $i\in [k]$. \\
		{\color{blue}\tcc{recompute $\widehat{w}^t$ \& draw new samples for $\mathcal{S}$ only if $w^t$ changes sufficiently.}}
		\If{there exists $j\in [k]$ such that $\sum_{\ell\in \mathcal{L}}u_{j,\ell}^t \geq 2\hat{w}_{j}^{t-1}$ \label{line:a1-obj}}{ 
			$\widehat{w}^t_{i} \leftarrow  \max\big\{\sum_{\ell\in \mathcal{L}}u_{i,\ell}^t, \widehat{w}^{t-1}_{i} \big\}$ for all $i\in [k]$; \\
			\For{$i=1,\ldots,k$}{  $n_i^t \leftarrow \left\lceil T_1 \widehat{w}^t_{i} \right\rceil$; \\
			draw $n_i^t - n_i^{t-1}$ independent samples from $\mathcal{D}_i$, and add these samples to $\weighteddata$.\label{line:sample1-obj}
			}
		}
		{\color{blue}\tcc{estimate the near-optimal hypothesis for weighted data distributions.}}
		compute $h^t\leftarrow \arg\min_{h\in \mathcal{H}} \widehat{L}^t(h,u^t)$, where 
		%
		\begin{align}
			\widehat{L}^t(h,u^t):=\sum_{i=1}^k\sum_{\ell\in \mathcal{L}} \frac{u^t_{i,\ell}}{n_i^t}\cdot \sum_{j=1}^{n_i^t}\ell\big(h,(x_{i,j},y_{i,j})\big)\label{eq:e1obj}
		\end{align}
		%
		with $(x_{i,j},y_{i,j})$ being the $j$-th datapoint from $\mathcal{D}_i$ in $\weighteddata$. \label{line:a2obj}
  \\
		{\color{blue}\tcc{estimate the loss vector and execute weighted updates.}}
		%
		$\overline{w}^t_i \leftarrow \max_{1\leq \tau \leq t}\sum_{\ell\in \mathcal{L}}u^{\tau}_{i,\ell}$ for all $i \in [k]$. \\
		\For{$i=1,\ldots, k$}{ 
		draw $ \lceil k\overline{w}^t_i \rceil$ independent samples --- denoted by $\big\{(x^t_{i,j},y^t_{i,j})\big\}_{j=1}^{\lceil k\overline{w}_i^t\rceil}$ --- from $\mathcal{D}_i$, and set \label{line:updateSobj} 
		$$
			\widehat{r}^t_{i,\ell} =\frac{1}{\lceil k\overline{w}^t_i\rceil}\sum_{j=1}^{\lceil k\overline{w}^t_i \rceil} \ell\big(h^t,(x_{i,j}^t,y_{i,j}^t) \big) \qquad \text{for each }\ell\in \mathcal{L}; 
		$$

		update the weight as $U^{t+1}_{i,\ell} = U^t_{i,\ell}  \exp(\eta \widehat{r}_{i,\ell}^t)$. \label{line:updateS12-obj} {\color{blue}\tcp{Hedge updates.}}
		}
	}
	\textbf{output:}  a randomized hypothesis $h^{\mathsf{final}}$ as a uniform distribution over $ \{h^t\}_{t=1}^T$.
\end{algorithm}
Lemma 27 (Fact): Given $\mathcal{W}_j$ and $(s_i,e_i)$ for $i\in \mathcal{W}_j$ defined above,  there exists  a group of subsets $\{\mathcal{V}_j^n\}_{n=1}^N$ such that the conditions below hold
\begin{enumerate}[label=(\roman*).]
\item $\mathcal{V}_j^n\subset \mathcal{W}_j$, $\mathcal{V}_j^n\cap \mathcal{V}_j^{n'}=\emptyset$, $\forall n\neq n'$; 
\item $\sum_{n=1}^N |\mathcal{V}_j^n|\geq \frac{|\mathcal{W}_j|}{24\log_2(k)(\log_2(T)+1)}$; 
\item There exists $1\leq \widehat{s}_1<\widehat{e}_1\leq \widehat{s}_2 <\widehat{e}_2\leq \dots \leq \widehat{s}_N <\widehat{e}_N\leq T$, and $\{g_n\}_{n=1}^N\in \left[1,\infty\right)^N$ such that for each $1\leq n \leq N$,  $(\widehat{s}_n,\widehat{e}_n)$ is a $\left(2^{-(j+1)}g_n|\mathcal{V}_j^n|,  2^{-(j+2)}|\mathcal{V}_j^n| , \frac{\log(2)}{2\log_2(k)}  \right)$-segment with index set as $\mathcal{V}_j^n$. That is, the following hold for each $1\leq n \leq N$:\begin{itemize}
    \item $\frac{g_n |\mathcal{V}_j^n|}{2^{j+2}}<\sum_{i\in \mathcal{V}_j^n} w_i^{\widehat{s}_n}\leq \frac{g_n |\mathcal{V}_j^n|}{2^{j+1}}$ ;
    \item $\frac{g_n|\mathcal{V}_j^n|}{2^{j}}\cdot \exp\left( \frac{\log(2)}{2\log_2(k)}\right)<\sum_{i\in \mathcal{V}_j^n}w_i^{\widehat{e}_n}$;
    \item $\sum_{i\in \mathcal{V}_j^n}w_i^{t}\geq \frac{|\mathcal{V}_j^n|}{2^{j+2}}$ for any $\widehat{s}_n \leq t\leq \widehat{e}_n$.
\end{itemize}


\end{enumerate}
Lemma 26 (Fact):  For each $i\in \mathcal{W}_j$, there exist $1\leq s_1<e_i \leq T$ satisfying $\frac{1}{2^{j+2}}<w_i^{s_i}\leq \frac{1}{2^{j+1}}$, $\frac{1}{2^j}<w_i^{e_i}$, and $w_i^t >2^{-(j+2)}$ for any $s_i \leq t\leq e_i$.

