Algorithm 1: \begin{algorithm}
    \caption{\colorbox{Thistle}{Adam with $\ell_2$ regularization} and \colorbox{SpringGreen}{Adam with decoupled weight decay (\adamw)}}\label{alg:adamw}
    \begin{algorithmic}
        \INPUT{$\beta_1, \beta_2>0$, initialization $\vx_0$, total steps $T$, learning rate schedule $\{\eta_t\}_{t=1}^T$, weight decay coefficient $\lambda$}
        \State $\vm_0 \gets \vec{0}, \vv_0 \gets \vec{0}$  
        \For{$t=1, 2, \cdots, T$}
        % \State $t \gets t+1$
        \State $\vg_t \gets \nabla L(\vx_{t-1})$\colorbox{Thistle}{$+\lambda \vx_{t-1}$}
        \State $\vm_t \gets \beta_1 \vm_{t-1} + (1-\beta_1) \vg_t$
        \State $\vv_t \gets \beta_2 \vv_{t-1} + (1-\beta_2) \vg_t^2$
        \State $\vx_t \gets \vx_{t-1} -\eta_t \frac{\vm_t}{\sqrt{\vv_t}}$\colorbox{SpringGreen}{$-\lambda \eta_t \vx_{t-1}$}
        \EndFor
        \State \Return $\vx_T$
    \end{algorithmic}
\end{algorithm}
Notations: We use $\norm{\cdot}$ to denote a general norm and $\norm{\cdot}_*$ to denote its dual norm. We say a function $L:\mathbb{R}^d\to \mathbb{R}$ has $H$-lipschitz gradient w.r.t. norm $\norm{\cdot}$ for some $H>0$ iff for all $\vx,\vy\in\mathbb{R}^d$, $\norm{\nabla L(\vx) - \nabla L(\vy)}_* \leq H \norm{\vx-\vy}$. We define the \emph{smoothness} of loss $L$ as the smallest positive $H$ w.r.t. $\norm{\cdot}$ such that $L$ has $H$-lipschitz gradient. We say a function $L:\mathbb{R}^d\to \mathbb{R}$ is convex iff for any $\vx,\vy\in\mathbb{R}^d$ and $\theta\in[0,1]$, it holds that $L(\theta\vx+(1-\theta)\vy)\le \theta L(\vx) + (1-\theta)L(\vy)$. We define the \emph{subgradients} of convex function $L$ at point $\vx$ as $\{\vg\in\mathbb{R}^d\mid L(\vy)\ge L(\vx)+\inner{\vy-\vx}{\vg},\forall \vy\in\mathbb{R}^d\}$, which is denoted by $\partial L(\vx)$. When $L$ is differentiable at $\vx$,  $\partial L(\vx)$ contains only one element, which is the gradient $\nabla L(\vx)$. In particular, all norms are convex functions
Definition 2.1: We say $\vv$ is a \emph{steepest descent direction} for objective function $L$ at current iterate $\vx$ w.r.t. norm $\norm{\cdot}$ iff $\norm{\vv} =1$ and $\inner{\vv}{\nabla L(\vx)} = \min_{\norm{\vv'}\le 1} \inner{\vv'}{\nabla L(\vx)}$. Thus for all steepest descent direction $\vv$, we have that $\inner{\vv}{\nabla L(\vx)} = -\norm{\nabla L(\vx)}_*$. 

Given initialization $\vx_0$, learning rate schedule $\{\eta_t\}_{t=0}^\infty$ and weight decay factor $\lambda$,
the $t$th iterate of \emph{normalized steepest descent} w.r.t. $\norm{\cdot}$ with decoupled weight decay is defined as 
\begin{equation}
    \vx_{t} = (1-\lambda \eta_t)\vx_{t-1} - \eta_t \vDelta_t  \text{, where } \vDelta_t \in \argmax_{\norm{\vDelta} \leq 1} \nabla L(\vx_{t-1})^\top \vDelta.
\end{equation} 
Lemma 3.1: For any learning rate schedule $\{\eta_t\}_{t=1}^\infty$ and update $\{\vDelta_t\}_{t=1}^\infty$ such that $\lambda \eta_t < 1$ and $\norm{\vDelta_t} \leq 1$, $\norm{\vx_t} - \frac{1}{\lambda} \le \max\left( e^{-\lambda \sum_{i=1}^{t} \eta_i } \left(\norm{\vx_0} - \frac{1}{\lambda} \right) ,0\right)$.
Definition 3.6: We say $\vx^*\in\mathbb{R}^d$ is a KKT point of the constrained optimization problem $\min_{\norm{\vx}\le \frac{1}{\lambda}} L(\vx)$ iff there exists $s^*\ge0$ such that $\norm{\vx^*}\le \frac{1}{\lambda}$, $0\in \nabla L(\vx^*)+ \partial (s^*\norm{\vx})\vert_{\vx=\vx^*}$, $s^*(\norm{\vx^*}-\frac{1}{\lambda})=0$.

