\begin{algorithmic}
    \STATE set hyperparameter $\eta_p = \tilde{O}\qty(\delta^{\frac{3}{2}} \wedge \frac{\delta^3}{\varepsilon}), ~T_\mathrm{thres} = \tilde{O}\qty(\frac{1}{\delta})$, and $F_{\mathrm{thres}} = \tilde{O}(\delta^3)$
    \STATE initialize $\mu^{(0)}$ and $t_p = - T_{\mathrm{thres}}$
    \FOR {$t>0$}
    \IF {$\norm{\nabla_{\mu} F (\mu_t)}_{L^2(\mu_t)} \leq \varepsilon$ and $t - t_\mathrm{p}>t_{\mathrm{thres}}$}
        \STATE $\xi \sim \mathrm{GP}(0,K_{\mu_t}), ~ \mu_t \gets (\id + \eta_p \xi) \sharp \mu_t, ~ t_{\mathrm{p}} \gets t$
    \ENDIF
    \IF{$t = t_{\mathrm{p}} + T_{\mathrm{thres}}$ and $F(\mu_{t_{\mathrm{p}}}) - F(\mu_t) \leq F_{\mathrm{thres}}$}
        \STATE \bf{return} $\mu_{t_{\mathrm{p}}}$
    \ENDIF
    \STATE $\partial_t \mu_t + \nabla \cdot \left (- \nabla_{\mu} F (\mu_t) \mu_t \right ) = 0$
    \ENDFOR
\end{algorithmic}
\end{algorithm}
Algorithm 2: \begin{algorithm}[tb]
    \caption{PWGF (discrete-time)}
    \label{alg_PWGD}
    \begin{algorithmic}
        \STATE set hyperparameter $\eta_p = \tilde{O}\qty(\delta^{\frac{3}{2}} \wedge \frac{\delta^3}{\varepsilon})$, $\eta = O(1), k_\mathrm{thres} = \tilde{O}\qty(\frac{1}{\delta})$, and $F_{\mathrm{thres}} = \tilde{O}(\delta^3)$
        \STATE initialize $\mu^{(0)}$ and $k_p = k_{\mathrm{thres}}$
        \FOR {$k = 0,1,...$}
            \IF {$\norm{\nabla_\mu F(\mu^{(k)})}_{L^2(\mu^{(k)})} \leq \varepsilon$ and $k - k_{\mathrm{p}} > k_{\mathrm{thres}} $}
                \STATE $\xi \sim \mathrm{GP}(0,K_{\mu^{(k)}}), ~ \mu^{(k)} \gets (\id + \eta_p \xi) \# \mu^{(k)}$
                \STATE $k_p \gets k$
            \ENDIF
            \IF {$k = k_{\mathrm{p}} + k_{\mathrm{thres}}$ and $F(\mu^{(k_{\mathrm{p}})}) - F(\mu^{(k)}) \leq F_{\mathrm{thres}}$}
                \STATE \bf{return} $\mu^{(k_{\mathrm{p}})}$
            \ENDIF
            \STATE $ \mu^{(k+1)} \gets (\id - \eta \nabla_{\mu} F(\mu^{(k)})) \# \mu^{(k)}$
        \ENDFOR
    \end{algorithmic}
\end{algorithm}
Assumption 3: $F$ satisfies the following smoothness:
    \begin{itemize}[leftmargin = 5mm]
        \item $\nabla_\mu F$ is $L_1$-Lipschitz, i.e. for any $\gamma \in \Gamma(\mu,\nu)$, 
        \begin{align}
            \label{grad_lipschitz}
            \textstyle \int \lVert \nabla_\mu F (\mu,x) -  \nabla_\mu F(\nu,y)\rVert^2 \gamma(\diff x \diff y) 
            \leq L_1^2 \int \norm{x-y}^2 \gamma(\diff x \diff y).
        \end{align}
        \item $\nabla_\mu^2 F$ is $L_2$-Lipschitz, i.e. for any $\gamma \in \Gamma(\mu,\nu)$,
        \begin{align}
            \label{hessian_lipschitz}
            \textstyle \int \lVert \nabla_\mu^2 F(\mu,x_1,x_2)  -  \nabla_\mu^2 F(\nu,y_1,y_2)\rVert^2 \gamma^{\otimes 2} (\diff x \diff y) 
            \leq L_2^2 \int \norm{x-y}^2 \gamma(\diff x \diff y).
        \end{align}
        \item $\nabla \nabla_{\mu} F$ is $L_3$-Lipschitz, i.e. for any $\gamma \in \Gamma(\mu,\nu)$,
        \begin{align}
            \label{hessian_lipschitz_beta}
            \textstyle \gamma \mathrm{-ess sup}_{x \in \R^d} ~ \lVert \nabla  \nabla_\mu F(\mu,x)  - \nabla \nabla_\mu F(\nu,y)\rVert^2
            \leq L_3^2 \int \norm{x-y}^2 \gamma(\diff x \diff y).
        \end{align}
    \end{itemize}
Definition B.1: The 2-Wasserstein distance between two points $\mu, \nu \in \P_2(\R^d)$ is defined as
    \begin{align}
        \label{appendix_wasserstein_metric}
        W_2(\mu,\nu)^2 \coloneq \inf_{\gamma \in \Gamma(\mu,\nu)} \int \norm{x - y}^2 \gamma(\diff x \diff y). 
    \end{align}
    Here, $\Gamma(\mu,\nu)$ represents the set of all transport plans:
    \begin{align*}
        \Gamma(\mu,\nu) = \left\{\gamma \in \P_2(\R^{d} \times \R^d) ~\middle | p_1 \# \gamma = \mu,~ p_2 \# \gamma = \nu \right \}.
    \end{align*}
    Moreover, $\gamma \in \Gamma(\mu,\nu)$ is called the optimal transport plan, if the infmum in \eqref{appendix_wasserstein_metric} is attained by $\gamma$. The set of all optimal transport plans is denoted by $\Gamma_o (\mu,\nu)$.
    Furthermore, if a measurable map $f : \R^d \to \R^d$ satisfies $(\id \times f)\sharp \mu \in \Gamma_o (\mu,\nu)$, then $f$ is called the optimal transport map between $\mu$ and $\nu$. 
    In this case, we denote the optimal transport map $f$ as $\otm{\mu}{\nu}$.
Proposition B.2 (Fact): For $ \mu, \nu \in \mathcal{P}_2(\mathbb{R}^d) $, there exists an optimal transport plan between $ \mu $ and $ \nu $. That is, there exists $ \gamma \in \Gamma(\mu, \nu) $ such that
    \begin{align*}
        W_2({\mu},{\nu})^2 = \int \|x - y\|^2 \, \gamma(\mathrm{d}x \mathrm{d}y).
    \end{align*}
Proposition B.3 (Fact): For any $\mu \in \P^a_2(\R^d)$ and $\nu \in \P_2(\R^d)$, there exists an optimal transport map $\otm{\mu}{\nu}:\R^d \to \R^d$. 
    Specifically, $\otm{\mu}{\nu}$ satisfies
    \begin{align*}
        W_2(\mu, \nu)^2 = \int \lVert\otm{\mu}{\nu}(x) - x\rVert^2 \mu(\diff x).
    \end{align*}
    Furthermore, the following hold:
    \begin{itemize}
        \item $\Gamma_o (\mu, \nu) = \{(\id \times \otm{\mu}{\nu})\sharp \mu \}$, that is, the unique optimal transport plan from $\mu$ to $\nu$ is induced by $\otm{\mu}{\nu}$. 
        \item The optimal transport map can be expressed as $\otm{\mu}{\nu} = \nabla \varphi$, where $\varphi$ is a convex function defined $\mu$-almost everywhere. 
        \item If $\nu \in \P^a_2(\R^d)$ as well, then $\otm{\nu}{\mu} \circ \otm{\mu}{\nu} = \id$ $\mu$-a.e. and $\otm{\mu}{\nu} \circ \otm{\nu}{\mu} = \id$ $\nu$-a.e.
    \end{itemize} 
Proposition B.4 (Fact): Let $\mu, \nu \in \P_2(\R^d)$, and $\gamma \in \Gamma_0(\mu,\nu)$. 
    Then $\mu_t = ((1 - t)p_1 + t p_2) \sharp \gamma$ defines a geodesic between $\mu$ and $\nu$, i.e.,
    \begin{align*}
        W_2(\mu, \mu_t) = t W_2(\mu, \nu) \quad (\forall t \in [0,1]). 
    \end{align*}
    In particular, in case where $\gamma$ is induced by an optimal transport map $\otm{\mu}{\nu}$, $\mu_t = ((1-t)\id + t \otm{\mu}{\nu}) \# \mu$ and $\otm{\mu}{\mu_t} = (1-t) \id + t \otm{\mu}{\nu}$ hold.
Definition B.5: Let $\mu_t \in \P_2(\R^d) ~ (t \in I)$ be a curve in Wasserstein space, and let $v_t \in L(\mu_t)^d ~ (t \in I)$ be the corresponding vector field.
    The curve $\mu_t$ is said to satisfy the continuity equation with respect to the vector field $v_t$ if the distribution equation: 
    \begin{align}
        \label{continuous_equation_appendix}
        \partial_t \mu_t + \nabla \cdot (v_t \mu_t) = 0
    \end{align}
    holds. Equation (\ref{continuous_equation_appendix}) means that for all $\phi \in C_0^\infty(\R^d)$,
    \begin{align*}
        \frac{\diff}{\diff t} \int \phi(x) \mu_t(\diff x) = \int \nabla \phi(x)^\top v_t(x) \mu_t(\diff x). 
    \end{align*}
Proposition B.6 (Fact):     Let $I \subset \R$ be an open interval, and let $\mu_t : I \to \P_2(\R^d)$ be a continuous curve. 
    $\mu_t$ is absolutely continuous, if and if only $\mu_t$ satisfies continuity equation (\ref{continuous_equation}) for some vector field $v_t \in L^2(\mu_t)$. 
Definition B.7: We define the tangent space $\tansp{\mu} \subset L^2(\mu)$ at $\mu \in \P_2(\R^d)$   as 
    \begin{align*}
        \tansp{\mu} \coloneq X_{\mu}^\perp = \overline{\left \{ \nabla \phi ~ \middle | ~ \phi \in C_0^\infty(\R^d) \right \} }^{L^2(\mu)}. 
    \end{align*}
Proposition B.8 (Fact):     For any \( \mu, \nu \in \mathcal{P}_2(\mathbb{R}^d) \) and \( T > 0 \), the following holds:
    \begin{align*}
        W_{2}({\mu},{\nu})^2 = \inf \left\{ T \int_0^T \|v_t\|_{L^2(\mu_t)}^2 \, \mathrm{d}t ~\middle|~ \partial_t \mu_t + \nabla \cdot (v_t \mu_t) = 0~(t \in (0,T)),~ \mu_0=\mu, \mu_T = \nu \right\}. 
    \end{align*}
Proposition B.9 (Fact): Let $\mu_t$ be an absolutely continuous curve satisfying continuous equation with vector field $v_t \in \tansp{\mu_t}$. Then, 
    \begin{align*}
        \lim_{h \to 0} \frac{W_2(\mu_{t+h},(\id + h v_t)\# \mu_t)}{h} = 0. 
    \end{align*}
Proposition B.10 (Fact): Suppose that $\mu \in \P_2(\R^d)$ and that $\varphi:\R^d \to \R$ is a  convex and $\mu$-a.e. differentiable function with $\nabla \varphi \in L^2(\mu)^d$. 
    Then, the map $\nabla \varphi$ provides the optimal transport map from $\mu$ to $(\nabla \varphi)\sharp \mu$. 
Definition B.13: The Wasserstein gradient $\nabla_\mu F : \P_2(\R^d) \times \R^d \to \R^d$ at $\mu \in \P_2(\R^d)$ is defined as a vector-field such that for any $\nu \in \P_2(\R^d)$ and $\gamma \in \Gamma_0(\mu,\nu)$, it holds that 
    \begin{align}
        \label{appendix_w_g}
        F(\nu) - F(\mu) 
        = \int \nabla_\mu F(\mu, x)^\top (y-x) \gamma(\diff x \diff y) + O\qty(W_2(\mu,\nu)^2). 
    \end{align}
    In particular, there exists a unique element that satisfies $\nabla_\mu F(\mu) \in \tansp{\mu}$ (\citet{lanzetti2022first} Proposition 2.5), and we take this as the Wasserstein gradient.
Definition B.14: The first variation $\var{F}{\mu} : \P_2(\R^d) \times \R^d \to \R$ is defined as a functional satisfying for any $\nu \in \P_2(\R^d)$, 
    \begin{align}
        \label{first_variation_appendix}
        \left . \frac{\diff}{\diff h} \right |_{h=0} F(\mu + h (\nu - \mu)) 
        = \int \var{F}{\mu} (\mu,x) (\mu - \nu) (\diff x). 
    \end{align}
    The first variation, if it exists, is unique up to a constant difference.
Definition B.15: Suppose that $\mu,~ \nu \in \P_2(\R^d)$. The total variation between $\mu$ and $\nu$ is: 
    \begin{align*}
        \mathrm{TV} (\mu,\nu) \coloneq \sup_{B \in \mathcal{B}(\R^d)} \qty|\mu(B) - \nu(B)| 
        = \frac{1}{2} \sup_{\mathcal{C} \subset \mathcal{B}(\R^d),\cup \mathcal{C}=\R^d} \sum_{B \in \mathcal{C}} \qty|\mu(B) - \nu(B)|.
    \end{align*}
Proposition C.1 (Fact): Let $F: \P_2(\R^d) \to \R$ be a functional on probability space, and differentiable at $\mu$. Then, for any transport plan $\gamma \in \Gamma(\mu,\nu)$ (not necessarily an optimal one),
    \begin{align*}
        F(\nu) - F(\mu) = \int \nabla_\mu F(\mu,x)^\top (y-x) \gamma(\diff x \diff y) + O\qty(\int \norm{x-y}^2 \gamma(\diff x \diff y)).
    \end{align*}
Proposition C.4 (Fact): Let $\mu^* \in \P_2(\R^d)$ be a local minimizer of a differentiable functional $F : \P_2(\R^d) \to \R$ i.e. it holds that there exists a constant $r > 0$ such that
    \begin{align*}
        W_2(\mu, \mu^*) < r \implies F(\mu) \leq F(\mu^*). 
    \end{align*}
    Then the Wasserstein gradient of $F$ vanishes at $\mu^*$:
    \begin{align*}
        \nabla_{\mu} F(\mu^*, x) = 0 \quad \mu^* \text{-a.e.} x,
    \end{align*}
    i.e. $\nabla_{\mu} F(\mu^*) = 0$ in $L^2(\mu^*)^d$.
Proposition C.5 (Fact):     Suppose that $F$ is differentiable and $\alpha$-geodesically convex with $\alpha \geq 0$, i.e. it holds that 
    \begin{align*}
        F(\nu) - F(\mu)  \geq \int \inpro{\nabla_{\mu}F(\mu, x)}{y-x} \gamma(\diff x \diff y) + \frac{\alpha}{2} W_2(\mu,\nu)^2 \quad \forall \gamma \in \Gamma_0(\mu,\nu).
    \end{align*}
    Then, $\nabla_{\mu} F(\mu^*) = 0 ~ \mu\text{-a.e.}$ implies that $\mu^*$ is global minimizer of $F$, i.e. $F(\mu) \geq F(\mu^*)$ holds for any $\mu \in \P_2(\R^d)$.
