Setup: A wide range of operations management problems are special cases of the following stochastic optimization model,
\begin{equation}\label{problem:math_original_extension}
\min_{x\in \mathcal{X}}~F(x) \coloneqq \mathbb{E}_{\xi\sim \PP(\xi)} [f(\phi(x,\xi))],
\end{equation}
where $\mathcal{X}  = [\munderbar{X}_1,\bar{X}_1]\times\ldots\times [\munderbar{X}_d,\bar{X}_d] \subseteq \RR^d$, $\xi\in\Xi \subseteq \RR^d$ is a random vector, $\phi(x,\xi)=(\phi_1(x_1,\xi_1),\dots,\phi_d(x_d,\xi_d))^\top$ is component-wise non-decreasing in $x$, and $f$ is convex.
In the following, we assume that the distribution $\PP(\xi)$ remains unknown, and we can only generate independent and identically distributed (i.i.d.) samples from $\PP(\xi)$.

\textcolor{black}{For an abuse of notation, let $\nabla$ denote derivative, (sub)gradient, {Clarke subdifferential}, and Jacobian. 
For $x,~u\in\RR^d$, and $\xi\in\Xi\subseteq \RR^d$, let $x=(x_1,\ldots,x_d)^\top$, $u=(u_1,\ldots,u_d)^\top$, $\xi=(\xi_1,\ldots,\xi_d)^\top$, where a subscript denotes the corresponding coordinate of a vector.  
We use \textcolor{black}{$\|\cdot\|$ to denote $l_2$ norm for vector and matrix. Note that the $l_2$ norm for a matrix is also known as the spectral norm, i.e., the largest singular value of a matrix. In addition, it holds that 
$\|\Lambda_1\Lambda_2\|\leq \|\Lambda_1\|\|\Lambda_2\|$ for any $\Lambda_1, \Lambda_2\in\RR^{d\times d}$.} Let $\Pi_\mathcal{X}(x):= \argmin_{y\in\mathcal{X}}\|y-x\|^2$ denote projection from $x$ onto set $\mathcal{X}$.
A function $f$ is $L_f$-Lipschitz continuous on $\mathcal{X}$ if it holds that $\|f(x)-f(y)\|\leq L_f\|x-y\|$ for any $x,y\in\mathcal{X}$. If the gradient of a function is Lipschitz continuous, we also call this function smooth. If a function $f$ satisfies $f(x)-f(y)-\nabla f(y)^\top (x-y)\geq \mu \|x-y\|^2$ for some constant $\mu$, we say $f$ is $\mu$-strongly convex if $\mu>0$, $f$ is convex if $\mu=0$, and $f$ is $\mu$-weakly convex if $\mu<0$. Note that any $S_f$-smooth function is also $\mu$-weakly convex by definition.
We use $[N] :=\{1,\dots,N\},~N\in\mathbb{N}^+$ to denote the set of subscript.} We use $\Lambda^{-\top}$ to denote the transpose of the inverse of a matrix $\Lambda$. We mainly focus on the complexity bounds in terms of the accuracy $\eps$: we use $\cO$ to hide constants that do not depend on the desired accuracy $\eps$ and use $\tilde \cO$ to further hide the $\log(\eps^{-1})$ term. 
Assumption 2.1: We assume
\begin{itemize}
    \item[(a).] Random vector $\xi\in\Xi\subseteq\RR^d$ is coordinate-wise independent.
    \item[(b).] Function $\phi_i(x_i,\xi_i)$ is non-decreasing in $x_i$ for any given $\xi_i\in\Xi_i$ and any $i\in[d]$.
    \item[(c).] Function $\{\phi_i(g^{-1}_i(u_i),\xi_i), u_i\in\mathcal{U}_i\}$ is \textit{stochastic linear in midpoint}\footnote{Definition 1 in \cite{feng2018supply}: A function $\{Y(x),x\in\mathcal{X}\}$ for some convex $\mathcal{X}$ is \textit{stochastically linear in midpoint} if, for any $x_1,x_2\in \mathcal{X}$, there exist $\hat{Y}(x_1)$ and $\hat{Y}(x_2)$ defined on a common probability space such that (i) $\hat{Y}(x_i)=^{d} Y(x_i),~i=1,2$ and (ii) $(\hat{Y}(x_1)+\hat{Y}(x_2))/2\leq_{cv} Y((x_1+x_2)/2)$ where $=^{d}$ denotes equal in distribution and $\leq_{cv}$ denotes concave order.} for any $i\in[d]$.
\end{itemize}
Assumption 2.2: We assume
\begin{enumerate}
    \item [(a)] Domain $\mathcal{X}$ has a finite radius $D_\mathcal{X}$, i.e., $\forall x\in\mathcal{X}, \|x\|\leq D_\mathcal{X}$.
    \item[(b)] Function $f$ is convex, $L_f$-Lipschitz continuous, and continuously differentiable.
    \item[(c)] Random function $\phi(x,\xi)$ is $L_\phi$-Lipschitz continuous in $x$ for any $\xi\in \Xi$.
    \item[(d)] {\color{black} For any $\xi\in\Xi$, random function $\phi(x,\xi)$ is differentiable in $x$ almost surely.}
\end{enumerate}
Assumption 2.3: For the transformation function $g:\mathcal{X}\rightarrow\mathcal{U}$, we assume 
\begin{enumerate}
    \item[(a)] {Function $g(x)$ is continuously differentiable for any $x\in\mathcal{X}$.}
    \item[(b)] Matrix $\nabla g(x)-\mu_g I$ is positive semi-definite for any $x\in\mathcal{X}$ and some constant $\mu_g>0$.
    \item[(c)]  Jacobian matrix  $\nabla g(x)$ is $S_g$-Lipschitz continuous in $x\in\mathcal{X}$, i.e., $\|\nabla g(x) - \nabla g(y)\|\leq S_g\|x-y\|$ for any $x,y\in\mathcal{X}$.
\end{enumerate}
\end{assumption} 
Algorithm 1: \begin{algorithm}[t]
	\caption{Regularized Stochastic Gradient (RSG)}
	\label{alg:RSG}
	\begin{algorithmic}[1]
		\REQUIRE  Number of iterations $ T $, stepsizes $\{\gamma_t\}_{t=1}^{T}$, initialization $x^1$, regularization $\lambda$.
		\FOR{$t=1$ to $T$ \do} 
		\STATE Draw a sample $\xi^t$ from $\mathbb{P}(\xi)$ and construct a gradient estimator
		\begin{center}
		$	
		v_\lambda(x^t)=\nabla \phi(x^t,\xi^t)^\top \nabla f(\phi(x^t,\xi^t)) + \lambda x^t.
		$   
		\end{center}
		\STATE Update $ x^{t+1}=\Pi_{\mathcal{X}}(x^t-\gamma_t v_\lambda(x^t))$.
		\ENDFOR
		\ENSURE $\hat x^T$ is selected uniformly from $ \{x^t\}_{t=1}^T$.
	\end{algorithmic}
\end{algorithm}
Algorithm 2: \begin{algorithm}[t]
	\caption{Mirror Stochastic Gradient (MSG)}
	\label{alg:MSG}
	\begin{algorithmic}[1]
		\REQUIRE  Number of iterations $ T $, stepsizes $\{\gamma_t\}_{t=1}^{T}$, initialization $x^1$, regularization parameter $\lambda$.
		\FOR{$t=1$ to $T$ \do} 
		\STATE Draw two independent samples $k_1$, $k_2$ uniformly from $\{0,\ldots,K-1\}$, draw i.i.d. samples $\{\tilde \xi^{ti}\}_{i=1}^{k_1}$, $\{\tilde \xi^{tj}\}_{j=1}^{k_2}$ to construct two estimators of $[\nabla g(x^t)]^{-1}$:
		$$
		[\nabla \hat g^{A}(x^t)]^{-1} = \frac{K}{2L_\phi} \Pi_{i=1}^{k_1} \Big(I - \frac{\nabla \phi(x^t,\tilde\xi^{ti})}{2L_\phi}\Big); \ [\nabla \hat g^{B}(x^t)]^{-1} = \frac{K}{2L_\phi} \Pi_{j=1}^{k_2} \Big(I - \frac{\nabla \phi(x^t, \tilde\xi^{tj})}{2L_\phi}\Big).
		$$
		(By convention, let $\Pi_{i=1}^{0} \Big(I - \frac{\nabla \phi(x^t,\tilde\xi^{ti})}{2L_\phi}\Big)=I$.)
		\STATE Draw a sample $\xi^t$ from $\mathbb{P}(\xi)$ and construct a gradient estimator
		\begin{center}
		$
		v_F(x^t)=[\nabla \hat g^{A}(x^t)]^{-\top}[\nabla \hat g^{B}(x^t)]^{-\top} \nabla \phi(x^t,\xi^{t})^\top \nabla f(\phi(x^t,\xi^{t})) + \lambda x^t.
		$
		\end{center}
		\STATE Update $ x^{t+1}=\Pi_{{\mathcal{X}}}(x^t-\gamma_t v_F(x^t))$.
		\ENDFOR
		\ENSURE $\hat x^T$ is selected uniformly from $ \{x^t\}_{t=1}^T$.
	\end{algorithmic}
\end{algorithm}

Set up: Throughout, bold font letters (e.g. $\vx$, $\vX$) to refer to vectors and matrices. 
Let $\langle\cdot,\cdot\rangle$ and $\lVert \cdot \rVert$ denote Euclidean inner product and  norm on $\R^d$.
For a probability measure $\nu$ on $\R^d$, we let $\langle f,g\rangle_{\nu} := \E_{\vX\sim\nu}[f(\vX)\cdot g(\vX)]$ and $\lVert f\rVert_{\nu} := \sqrt{\langle f,f\rangle_{\nu}}$ denote the inner-product and norm on the function space $L_{2}(\nu)$. 
The operator norm of a matrix $\vM$ (with respect to Euclidean norm) is denoted by $\lVert\vM\rVert_{\op}$.
For a positive integer $d$, we use $[d]$ to denote the set $\{1,\ldots,d\}$. 
Definition 2.1: A \emph{mean dimension-reduction subspace} for $\E[Y \mid \vX]$ is a subspace $W \subseteq \R^d$ such that $\E[Y \mid \vX]$ is a function only of $\vV^\T \vX$ for some matrix $\vV$ whose columns form a basis for $W$.
  Define
  \begin{equation*}
    \minspace:= \bigcap \{ W \subseteq \R^d : \text{$W$ is a mean dimension-reduction subspace for $\E[Y \mid \vX]$} \}.
  \end{equation*}
  We say $\minspace$ is the \emph{central mean subspace (CMS)} for $\E[Y \mid \vX]$ if $\minspace$ is a mean dimension-reduction subspace.
  (If $\minspace$ is not a mean dimension-reduction subspace, then the CMS does not exist.)
Definition 2.2:     Given an orthogonal matrix $\vU$ and its estimate $\widehat\vU$ (which is also orthogonal), the distance with optimal rotation between them defined as:
        $$d(\widehat\vU, \vU) := \min_{\vR \in \cO^{k \times k}} \lVert \widehat\vU \vR - \vU\rVert_{\op}\,, $$
    where $\cO^{k \times k}$ is the set of all $k \times k$ orthogonal matrices. 

Assumption 1:     The joint distribution $P_{\vX,Y}$ satisfies the following basic conditions. 
    \begin{enumerate}[label={(\arabic*)}, ref={(\arabic*)}]
        \item \label{assume:basic:differentiable}The link function $f$ is differentiable, with gradient $\nabla f(\vz), \forall \vz \in \R^{k}$; 
        \item \label{assume:basic:support} The marginal $P_{\vX}$ admits a Lebesgue density $p$ supported on $\R^d$, i.e., $p> 0$ everywhere.
    \end{enumerate}

Definition 3.1: The {Expected Smoothed Gradient Outer Product (ESGOP)} $\ESGOP$ is defined as follows.
First, let $h>0$ be given,
and define the \emph{smoothed gradient} of $g$ at $\shift \in \R^d$ as: 
\begin{align*}
    \vbeta_h(\shift) &:= \vU \cdot \Egrad{h}(\shift), \quad \text{where } \Egrad{h}(\shift):= \E_{\vZ \sim \Normal(\vzero_d, h^2 \vI_d)}[\nabla f(\vU^{\T}(\vZ+\shift))].  
\end{align*} 
Let $\sigma_\theta>0$. We then have: 
\begin{equation} \label{eqn:M}
    \ESGOP := \E_{\shift \sim \Normal(\vzero_d, \sigma_\theta^2 \vI_d)} \left[\vbeta_h(\shift) \vbeta_h(\shift)^{\T}\right] = \vU\left(\E_{\shift \sim \Normal(\vzero_d, \sigma_\theta^2 \vI_d)}\left[  \Egrad{h}(\shift)\Egrad{h}(\shift)^\T\right]\right) \vU^\T.
\end{equation}
Definition 3.3:     Let $m, h > 0$, and let 
    $\shift_1, \ldots, \shift_m \overset{i.i.d.}{\sim} \Normal(\vzero_d, \sigma_{\theta}^2 \vI_d)$. The Average Smoothed Gradient Outer Product (ASGOP) is obtained as: 
    \begin{align}
    \label{eqn:asgop}
        \ASGOP 
        := \frac{1}{m} \sum_{j=1}^m \vbeta_h(\shift_j) \vbeta_h(\shift_j)^{\T} 
        = \vU\left(\frac{1}{m} \sum_{j=1}^m\left[  \Egrad{h}(\shift_j)\Egrad{h}(\shift_j)^\T\right]\right) \vU^\T.
    \end{align}

