Algorithm 3.1: \begin{algorithm}[t!]
\caption{Estimation of the CMS $\minspace$}\label{alg:main}
\setstretch{1.35} \small 
\begin{algorithmic}[1]
    \vspace{.5em}
    \State \textbf{Input:} {$h > 0, \sigma_\theta > 0, m \in \mathbb{Z}$, dataset $\Data \subset \R^d \times \R$} 
    \State Randomly sample $\{\shift_{j}\}_{j=1}^{m}$ from $\Normal(\vzero_d, \sigma_\theta^2 \vI_d )$ 
    \State Split $\Data$ into  $\Data_{1}$, $\Data_{2}$, \ldots, and $\Data_{m}$ with equal sizes

    \State Split each $\Data_{j}$ into $\Data_{j, 1}$ and $\Data_{j, 2}$ with equal sizes

    \State $\forall j \in [m]$, let $\hat{\vbeta}_{j,1} \gets \hat{\vbeta}_h(\shift_{j}, \Data_{j, 1})$, and  $\hat{\vbeta}_{j,2} \gets \hat{\vbeta}_h(\shift_{j}, \Data_{j,2})$, where \hat{\vbeta}_h(\shift_j; \Data_{j, \ell}) := \frac{h^{-2}}{|\Data_{j, \ell}|}\sum_{(\vX, Y) \in \Data_{j, \ell}} \rho_h(\vX; \shift_j) \cdot Y \cdot (\vX-\shift_j)

    \State $\estimator \gets \frac{1}{2m}\sum_{j=1}^{m}(\hat{\vbeta}_{j,1}\hat{\vbeta}^{\T}_{j,2}+\hat{\vbeta}_{j,2}\hat{\vbeta}^{\T}_{j,1})$ 
    \State \textbf{Return:} {$\widehat{\vU} \in \R^{d \times k}$, the top-$k$ eigenvectors of $\estimator$}

\end{algorithmic}
\end{algorithm}

