Assumption 1: We use $\xB\in\Rbb^d$ to denote a feature vector and $y\in\{\pm 1\}$ to denote a binary label, respectively.
Let $(\xB_i,y_i)_{i=1}^n$ be a set of training data. 
Throughout the paper, we assume that $(\xB_i,y_i)_{i=1}^n$ is \emph{linearly separable}

Assume there is $\wB\in\Rbb^d$ such that $y_i \xB_i^\top \wB > 0$ for $i=1,\dots,n$.
Definition 1: Let $\wB\in\Rbb^d$ be the parameter of a linear model. 
In \emph{logistic regression}, we aim to minimize the following empirical risk
\begin{equation*}
    L(\wB) :=  \sum_{i=1}^n \log\big(1+\exp(-y_i\cdot \la \xB_i, \wB\ra ) \big),\quad  \wB\in\Rbb^d.
\end{equation*}
% \paragraph{Gradient descent.}
We study a sequence of iterates $(\wB_t)_{t\ge 0}$ produced by constant-stepsize \emph{gradient descent} (GD), where $\wB_0$ denotes the initialization and the remaining iterates are sequentially generated by:
\begin{align}
    \wB_{t} &= \wB_{t-1} - \eta\cdot \grad L(\wB_{t-1}),\quad   t\ge 1, \label{eq:gd} \tag{$\mathrm{GD}$}
\end{align}
where $\eta>0$ is a constant stepsize.
We are especially interested in a regime where $\eta$ is very large such that $L(\wB_t)$ oscillates as a function of $t$.
For the simplicity of presentation, we will assume that $\wB_0 = 0$. Our results can be easily extended to allow general initialization. 

Under Assumption 1, define the following notations:
\begin{enumerate}[label=(\Alph*),leftmargin=*,nosep]
    \item 
Let $\gamma$ be the max-$\ell_2$-margin (or max-margin in short), i.e.,
\[
\gamma := \max_{ \| \wB\|_2 = 1 } \min_{i\in [n]} \ y_i \cdot \la \xB_i, \wB\ra.
\]
\item 
Let $\hat\wB$ be the hard-margin support-vector-machine (SVM) soluion, i.e.,
\begin{align*}
    \hat\wB := \arg\min_{\wB\in\Rbb^d} \| \wB\|_2 ,\ \ \text{s.t.} \ \  y_i \cdot \la \xB_i, \wB\ra \ge 1,\ i=1,\dots,n.
\end{align*}
It is clear that $\hat\wB$ exists and is uniquely defined (see, e.g., Section 5.2 in \citet{mohri2018foundations}).
Note that $\| \hat\wB \|_2 = \gamma$ and $\hat\wB / \|\hat\wB\|_2$ is a max-margin direction. 
Also note that by duality, $\hat\wB$ can be written as (see, e.g., Section 5.2 in \citet{mohri2018foundations})
\[\hat\wB = \sum_{i\in\Scal} \alpha_i\cdot y_i \xB_i,\quad  \alpha_i \ge 0.\]
\item 
Let $\Scal$ be the set of indexes of the support vectors, i.e., 
\[\Scal := \{i\in [n]:   y_i \cdot \la \xB_i, \hat\wB / \| \hat\wB\|_2\ra  = \gamma\}.\]
\item 
If there exists non-support vector ($\Scal \subsetneq [n]$),
let $\theta$ be the second smallest margin, i.e., 
\[\theta := \min_{i\notin\Scal}\ y_i \cdot \la \xB_i, \hat\wB / \|\hat\wB\|_2\ra.\]
\end{enumerate}
It is clear from the definitions that $\theta>\gamma>0$.
In addition, from the definitions we have 
\[
\sum_{i\in\Scal}\alpha_i = \sum_{i\in\Scal}\alpha_i \cdot y_i \xB_i^\top \hat\wB = \|\hat\wB\|^2_2 = \frac{1}{\gamma^2}.
\]
Assumption 2: Assume that: 
\begin{enumerate}[label=(\Alph*),leftmargin=*,nosep]
    \item \label{assump:item:bounded}
\( \| \xB_i \|_2\le 1, \ i=1,\dots,n.\)
\item \label{assump:item:fullrank}
\(\rank\{ \xB_i,\ i=1,\dots,n\} = d.\)
\end{enumerate}
Assumption 3: \begin{enumerate}[label=(\Alph*),leftmargin=*,nosep]
    \item\label{assump:item:support-full-rank}  \( \rank\{ \xB_i,\ i\in \Scal\} = \rank\{\xB_i,\ i=1,\dots,n\} .\)
\item\label{assump:item:support-positive} There exist $\alpha_i>0, i\in\Scal$ such that $\hat\wB = \sum_{i\in\Scal} \alpha_i\cdot y_i \xB_i$.
\end{enumerate}
Lemma 3.1 (Fact): Suppose that Assumptions 1, 2, and 3 hold.
Then $(\xB_i, y_i)_{i\in\Scal}$ is not linearly separable in the subspace orthogonal to the max-margin direction $\hat\wB / \| \hat \wB\|_2$.
That is, 
\[
\text{for every}\ \vB \  \text{such that}\ \la \vB, \hat\wB \ra = 0,\  \text{there exist} \ i, j \in\Scal \ \text{such that}\
y_i\cdot \la \xB_i, \vB\ra  < 0,\ 
y_j\cdot \la \xB_j, \vB\ra > 0.
\]
Definition 2: Under Assumptions 1, 2, and 3, it holds that 
$\big( \bar\Pcal (\xB_i), y_i\big)_{i\in\Scal}$ is non-separable.
Let $b$ be a \emph{margin offset} such that
\[-b := \max_{\bar\wB \in \Rbb^{d-1}, \ \|\bar\wB\|_2=1}\min_{i\in\Scal} \ \ y_i \cdot  \big\la \bar\Pcal(\xB_i),\ \bar\wB \big\ra. \]
Then $b>0$ due to the non-separability.
The definition immediately implies that: 
\[\text{for every}\ \bar\vB \in\Rbb^{d-1},\ \text{there exists}\ i\in\Scal\ \text{such that}\
 y_i\cdot \big\la \bar\Pcal (\xB_i),\ \bar\vB \big\ra \le -b\cdot \| \bar\vB \|_2.\]
Lemma B.2: Suppose that Assumptions 1, 2, and 3 hold.
Consider $(\bar\wB_t)_{t\ge 0}$ defined by \eqref{eq:gd:decomposed} with constant stepsize $\eta > 0$.
Then for every $t\ge 0$, there exists $j\in[n]$ such that
    \begin{align*}
    \|\bar\wB_{t+1}\|_2^2 
    \le \| \bar\wB_t \|_2^2 + 2\eta e^{-w_t \gamma}\cdot \bigg( n-\frac{b\cdot \| \bar\wB_t \|_2}{4} \bigg) + \frac{\eta}{1+e^{w_t x_j + \bar\wB_t^\top \bar\xB_j}} \cdot \big(\eta n^2-b\cdot \| \bar\wB_t \|_2  \big).
\end{align*}
As a direct consequence, 
\begin{align*}
    \|\bar \wB_t \|_2 \ge \max\{ 4n/b,\ \eta n^2 /b \}\quad  \text{implies that} \quad \|\bar\wB_{t+1} \|_2\le \|\bar\wB_t\|_2.
\end{align*}
Definition 3: Under Assumptions \ref{assump:separable}, \ref{assump:bounded+fullrank},  and \ref{assump:non-degenerate},
we define the following notations:
\begin{enumerate}[label=(\Alph*),leftmargin=*]
\item 
Define two loss functions 
\begin{align*}
    G(\bar\wB) := \sum_{i \in \Scal} e^{-\bar\wB^\top \bar\xB_i}, \qquad  
    H(\bar\wB) := \sum_{i \notin \Scal } e^{-\bar\wB^\top \bar\xB_i}.
\end{align*}
In the case where $\Scal = [n]$, we define $H(\bar\wB) = 0$.

\item 
Define 
\[G_{\min} := \min_{\bar\wB \in \Rbb^{d-1}} G(\bar\wB),\]
It is clear that $G_{\min} \ge 1$ since $(\bar\xB_i)_{i \in \Scal}$ are non-separable by Definition \ref{def:offset}.

\item 
Define 
\[\bar\wB_* := \arg\min_{\bar\wB \in \Rbb^{d-1}} G(\bar\wB). \]
It is clear that $G(\bar\wB_*) = G_{\min}$.
Moreover, it holds that $\|\bar\wB_* \|_2 \le W_{\max}$ by Lemma \ref{lemma:ns:bar-w-star}.

\item 
Recall that $\|\bar\wB_t \|_2 \le W_{\max}$ according to Lemma \ref{lemma:ns:bounded-iter}.
We then define
\begin{align*}
    G_{\max} := \sup_{\|\bar\wB \|_2 \le W_{\max}} G(\bar\wB),\qquad 
     H_{\max} := \sup_{\|\bar\wB \|_2 \le W_{\max}} H(\bar\wB).
\end{align*}
It is clear that 
\[G(\bar\wB_t) \le G_{\max},\qquad 
H(\bar\wB_t) \le H_{\max},
\]
and that $G_{\max},\ H_{\max}$ are polynomials on $e^{\eta}$, $e^{n}$, and $e^{1/b}$, and are independent of $t$.
\end{enumerate}

